INSERT INTO `articles` VALUES (1,'الدراسة في تركيا','aldras-fy-trkya','تعد الدراسة في تركيا خياراً استراتيجياً جاذباً للطلاب الدوليين بفضل الاعتراف الدولي بالشهادات التركية وتطبيقها لنظام التعليم الاوربي، إلى جانب التوازن المثالي بين جودة التعليم والتكاليف الاقتصادية المناسبة مقارنة باوروبا\r\n\r\n<h2>أنواع الجامعات</h2>\r\n\r\n<h3>جامعات حكومية</h3>\r\nتمتاز الجامعات الحكومية في تركيا بتقديم تعليم ذي جودة أكاديمية عالية و تصنيفات عالمية،وبأقل تكلفة مالية ممكنة مقارنةً بالجامعات الخاصة .\r\nبالرغم من ذلك القبول فيها تنافسي للغاية يخضع لشروط محددة ونظام المفاضلات .\r\n\r\n<h3>جامعات خاصة</h3>\r\nهي مؤسسات تعليم عالي غير ربحية،تعتمد في تمويلها بشكل أساسي على الرسوم الدراسية المدفوعة من قبل الطلاب .\r\nكما تقدم العديد من التسهيلات مقارنةً بالجامعات الحكومية،وتقدم بعض الخصومات العالية،وقد يتم التعامل معها عن طريق المكاتب .','articles/g64PPbZtZIl4UOAqijuYA5KMkWTrVh4XmJcPLisc.jpg','turkey-studies','beginner',NULL,2,1,6,'2026-05-23 04:20:47','2026-06-07 07:53:41'),(2,'الفرق بين الجامعات الحكومية و الخاصة','lfrq-byn-ljmt-lhkwmy-at-w-lkhs-at','الفرق بينهما يتمثل في مجموعة من الأمور التي تختلف بين كلاً منهما :\r\n<h3>الرسوم</h3>\r\nفي الجامعات الحكومية تكون التكلفة برسوم سنوية تختلف من جامعة لأخرى، لكنها بشكل عام أقل من الجامعات الخاصة ،حيث تختلف الرسوم في الجامعات الخاصة بحسب اختلاف الجامعة و التخصص.\r\n\r\n<h3>شروط القبول </h3>\r\nتكون الشروط المطلوبة في الجامعات الحكومية أصعب بمراحل من الشروط بالجامعات الخاصة ،حيث تعتمد الجامعات الحكومية بشكل أساسي على اختبارات قبول معينة مثل /SAT & TRYÖS/  بالإضافة إلى معدل الثانوية .\r\n\r\n<h3>الترتيب الأكاديمي</h3>\r\nتتميز الجامعات الحكومية بترتيب أكاديمي أعلى دائماً من الجامعات الخاصة .\r\n\r\n<h3>فرص القبول </h3>\r\nتعد فرص القبول في الجامعات الخاصة أعلى من الجامعات الحكومية ، وذلك لسهولة الشروط التي تفرضها الجامعات الخاصة .\r\n\r\n\r\n\r\n<h3>محلاحظة</h3>\r\n\r\nالشهادات الصادرة عن كلا الجامعتين الحكومية والخاصة معترف بها عالمياً .','articles/PCLThBaLVjundrFtyqw64Abkd6nWNBjNsHua44Xi.jpg','turkey-studies','beginner',NULL,2,1,4,'2026-05-23 05:46:52','2026-06-07 07:53:34'),(3,'شهادة التومر(TÖMER)','shhad-altomr','<h3>تعريف</h3>\r\nهي شهادة لغة تركية ،تعتبر دليل معترف به على إتقان اللغة التركية ،وهي مطلب أساسي للدراسة في الجامعات التركية الحكومية منها والخاصة في البرامج التي تدرس باللغة التركية.\r\nتعتبر هذه الشهادة من أهم المستندات التي تساعد الاجانب في الحصول على فرصة عمل .\r\n\r\n<h3>أقسامها </h3>\r\nتتم دراسة شهادة التومر عبر أربعة أقسام :\r\n<ul>\r\n    <li></li>\r\n</ul>القراءة          Reading\r\n<ul>\r\n    <li></li>\r\n</ul>الكتابة           Writing\r\n<ul>\r\n    <li></li>\r\n</ul>الاستماع        listening\r\n<ul>\r\n    <li></li>\r\n</ul>التحدث         Spaeking\r\n\r\n<h3>مستويات</h3>\r\nتقسم شهادة التومر إلى خمسة مستويات أساسية ،ويكون المستوى السادس خاص فقط لطلاب الدراسات العليا :\r\n+A1_A2_B1_B2_C1_C2','articles/CaKV6Y6QVorgO9ujbucG5JaZ4PASv7iyv1xuODOQ.png','certificates','beginner',NULL,2,1,5,'2026-05-23 06:27:14','2026-05-23 09:03:42'),(4,'شهادة التوفل (TOEFL)','shhad-altofl','<h3>تعريف</h3>\r\nهي شهادة لغة انكليزية ،تعتبر واحدة من أشهر الشهادات العالمية لقياس كفاءة اللغة الانكليزية،تعتبر شرط رئيسي للأشخاص الأجانب الراغبين في دراسة البرامج باللغة الانكليزية .\r\n\r\n<h3>الاقسام</h3>\r\nتقسم شهادة التوفل إلى أربعة أقسام رئيسية :\r\n<ul>\r\n    <li></li>\r\n</ul>محادثة     Spaeking<ul>\r\n    <li></li>\r\n</ul>\r\nكتابة Writing<ul>\r\n    <li></li>\r\n</ul>\r\nقراءة Reading<ul>\r\n    <li></li>\r\n</ul>\r\nاستماعListening<ul>\r\n    <li></li>\r\n</ul>\r\n  \r\n<h3>أنواع التوفل</h3>\r\nيقسم التوفل إلى نوعين أساسيين:\r\n<ul>\r\n    <li></li>\r\n</ul>محليITP : هو اختبار ورقي يتم في جامعات أو مؤسسات محددة لأغراض داخلية مثل :تخرج أو توظيف محلي ، غير معترف بها عالميا ، صالحة لمدة سنتين من تاريخ ظهور النتيجة .\r\n<ul>\r\n    <li></li>\r\n</ul>عالميIBT : هو امتحان يتم تقديمه اونلاين عن طريق مراكز معتمدة في بريطانيا تحت رقابة الكترونية صارمة ، تكون صلاحيته دائمة \r\n\r\n<h2>معلومات عن الامتحان</h2>\r\nتستغرق مدة الاختبار الإجمالية حوالي ساعتين وتقسم إلى:\r\n<ul>35 دقيقة لاختبار القراءة ، تتضمن قراءة مقطعين أكاديميين ، أما الأسئلة فتكون حوالي 20 سؤال مؤتمت تقيس فهم المفردات والقدرة على تحليل النصوص .\r\n    <li></li>\r\n</ul>36 دقيقة لاختبار الاستماع ، تتضمن الاستماع إلى محاضرات ونقاشات أكاديمية ، أما الأسئلة فتكون 28 سؤال تقيس مدى فهم الطالب للأفكار والتفاصيل .\r\n<ul>16 دقيقة لاختبار المحادثة ، ويتكون من أربعة مهام ثلاثة منها متكاملة تتطلب القراءة والاستماع ثم التحدث عبر الميكروفون لشرح الفكرة ، و مهمة واحدة مستقلة تنص على التعبير عن رأيك في موضوع عام .\r\n    <li></li>\r\n</ul>\r\n<ul>\r\n    <li></li>\r\n</ul>29 دقيقة لاختبار الكتابة ، تتضمن مهمتين منفصلتين ؛ الأولى متكاملة تتضمن قراءة نص واستماع لمحاضرة ثم كتابة مقارنة بينهما ، أما الثانية فهي كتابة نقاش أكاديمي . \r\n<ul>تعد الدرجة الإجمالية لشهادة التوفل 120 درجة وهي مجموع الأقسام الأربعة حيث تكون علامة كل قسم 30 درجة.','articles/Y4af8vVpqUVJhUqFDJaY5VfabEK4Gp4hajIPHxAp.jpg','certificates','beginner',NULL,2,1,6,'2026-05-23 07:24:49','2026-05-23 09:25:05'),(5,'شهادة الايلتس (IELTS)','shhad-alaylakadts','<h3>تعريف</h3>\r\nهي شهادة لغة انكليزية ، تستخدم لقياس كفاءة الشخص باللغة الانكليزية ، تطلب في الجامعات التركية من طلاب الدراسات العليا بشكل دائم للبرامج التي تدرّس باللغة الانكليزية .\r\n\r\n<h3>انوعه</h3>\r\nيقسم إلى نوعين رئيسين حسب الهدف :\r\n<ol>\r\n    <li></li>\r\n</ol>\r\nأكاديمي : وهو مخصص للطلاب الراغبين في الدراسة الجامعية أو التسجيل في الهيئات المهنية الطبية والهندسية \r\n<ol>\r\n    <li></li>\r\n</ol>العام :وهو مخصص لأغراض الهجرة أو العمل أو التدريب المهني غير الأكاديمي.\r\n\r\n<h3>أقسامه</h3>\r\nيقسم الايلتس إلى أربع أقسام رئيسي :<ul>\r\n    <li></li>\r\n</ul>\r\nمحادثة Spaeking\r\n<ul>\r\n    <li></li>\r\n</ul>كتابة Writing\r\n<ul>\r\n    <li></li>\r\n</ul>قراءة Reading\r\n<ul>\r\n    <li></li>\r\n</ul>استماع Listening\r\n\r\n<h3>معلومات عن الامتحان </h3>\r\nيستغرق الامتحان كاملاً حوالي ساعتين و 45 دقيقة ويقسم إلى :<ul>\r\n    <li></li>\r\n</ul>30 دقيقة اختبار الاستماع ، يتم فيه الاستماع إلى أربعة تسجيلات صوتية مختلفة بين نصوص أكاديمية ومحادثات وبلكنات مختلفة مثل : البريطانية والاسترالية ، أما بالنسبة للأسئلة فهي 40 سؤال متنوع بين ملئ الفراغات والأتمتة <ul>\r\n    <li></li>\r\n</ul>60 دقيقة لاختبار القراءة ، يتضمن ثلاثة نصوص طويلة إما أن تكون أكاديمية أو من الحياة اليومية والعمل .\r\n أما بالنسبة للأسئلة فهي 40 سؤال تعتمد على قياس فهم الطالب للرسائل الضمنية <ul>\r\n    <li></li>\r\n</ul>60 دقيقة لاختبار الكتابة ، يتكون من مهمتين : الأولى إما أن يطلب كتابة وصف رسم بياني أو جدول (150 كلمة ) أو يطلب كتابة رسالة خطاب . والثانية يطلب كتابة مقال تعبر عن رأيك في قضية معينة (250 كلمة ) .<ul>\r\n    <li></li>\r\n</ul>بين 11 إلى 14 دقيقة لاختبار المحادثة ، تكون مقابلة حية وجهاً لوجه مع متقدم حقيقي وتنقسم إلى ثلاثة أجزاء : <ul>\r\n    <li></li>\r\n</ul>أسئلة عامة عن نفسك <ul>\r\n    <li></li>\r\n</ul>تحدث عن موضوع محدد لمدة دقيقتين <ul>\r\n    <li></li>\r\n</ul>نقاش عميق مع المتقدم حول الموضوع \r\n\r\n<h3>ملاحظة </h3>\r\nلايوجد في الايلتس نجاح أو رسوب إنما يتم التقيم بنظام الدرجات من1 الى 9 لكل قسم .','articles/D6pk87X71qRTu3MkwOopfWScUtBXXwFZqQVMTetK.jpg','certificates','beginner',NULL,2,1,4,'2026-05-23 07:46:24','2026-05-23 09:44:45'),(6,'منحة الحكومية التركية','mnh-alhkomy-altrky','<h3>تعريف</h3>\r\nمنحة مقدمة من الحكومية التركية عبر الجامعات الحكومية وبعض الجامعات الخاصة للطلاب الأجانب الراغبين في الدراسة في تركيا .\r\n\r\n<h3>التاريخ </h3>\r\nيبدأ التسجيل على المنحة بشكل ثابت سنويا 20 \\1 وينتهي التقديم عليها 20\\2\r\n\r\n<h3>ميزاتها</h3>\r\n<ul>\r\n    <li></li>\r\n</ul>\r\nتأمين قبول جامعي <ul>\r\n    <li></li>\r\n</ul>راتب شهري<ul>\r\n    <li></li>\r\n</ul>تأمين السكن<ul>\r\n    <li></li>\r\n</ul>تسديد رسوم القسط الجامعي <ul>\r\n    <li></li>\r\n</ul>تأمين صحي <ul>\r\n    <li></li>\r\n</ul>تأمين تذاكر الطيران <ul>\r\n    <li></li>\r\n</ul>دراسة اللغة <ul>\r\n    <li></li>\r\n</ul>\r\n\r\n<h3>شروط التقديم </h3>\r\n<ul>\r\n    <li></li>\r\n</ul>\r\nألا يكون حاصل على الجنسية التركية <ul>\r\n    <li></li>\r\n</ul>ألا يكون طالب في الجامعات التركية <ul>\r\n    <li></li>\r\n</ul>أن يكون أقل من 21 سنة للبكلوريوس <ul>\r\n    <li></li>\r\n</ul>أن يكون أقل من 30 سنة للماجستير <ul>\r\n    <li></li>\r\n</ul>أن يكون أقل من 35 سنة للدكتوراه<ul>\r\n    <li></li>\r\n</ul>أن يكون المعدل أكثر من 70 للبكلوريوس <ul>\r\n    <li></li>\r\n</ul>أن يكون المعدل أكثر من 80 للماجستير <ul>\r\n    <li></li>\r\n</ul>أن يكون المعدل أكثر من 90 للدكتوراه \r\n\r\n<h3>الأوراق المطلوبة</h3>\r\nصورة عن الهوية أو جوز السفر <ul>\r\n    <li></li>\r\n</ul>\r\nصورة شخصية <ul>\r\n    <li></li>\r\n</ul>صورة عن الشهادة الثانوية <ul>\r\n    <li></li>\r\n</ul>شهادات داعمة إن وُجد <ul>\r\n    <li></li>\r\n</ul>شهادات اللغة إن وُجد <ul>\r\n    <li></li>\r\n</ul>خطاب النوايا <ul>\r\n    <li></li>\r\n</ul>رسالة التوصية <ul>\r\n    <li></li>\r\n</ul>','articles/JGQhVIXpDX9VqpVHsnDbgoLdpO6Fq1bi5Myot0ir.png','scholarships','beginner',NULL,2,1,4,'2026-05-23 08:43:49','2026-06-07 09:17:53'),(7,'المنحة الجزئية','almnh-algzyy','<h3>تعريف</h3>\r\nهي منحة دراسية مقدمة من الجامعات الخاصة التركية .\r\nوهي أن يدفع الطالب الرسوم الدراسية لكافة السنوات كاملة دفعة واحدة بخصم قد يصل إلى 50 % أو أكثر،\r\n بتخصصات متنوعة مثل (الأفرع الطبية والهندسات )\r\nبعض الجامعات تشمل السنة التحضيرية لدراسة اللغة ضمن المنحة وبعضها الآخر لا يشملها بحيث يكون على الطالب دفع رسوم السنة التحضيرية خارج المنحة.','articles/mqKJQ9vHaCtRLn1tKoobbuITl2zWtJEwJN3cL61i.jpg','scholarships','beginner',NULL,2,1,2,'2026-05-23 08:58:46','2026-06-07 09:20:11'),(8,'يوس YÖS','yos-yos','<h3>التعريف</h3>\r\nهو امتحان قبول مخصص للطلاب الأجانب الراغبين في الدراسة في الجامعات التركية وخاصة الحكومية منها ،بدأ اعتماده في 2016 لغاية 2022 حيث تم الغاء العمل به و استبداله بامتحان قبول آخر (TR YÖS ) \r\n\r\n<h3>أقسامه </h3>\r\nيقسم اليوس إلى ثلاثة أقسام رئيسية :<ul>\r\n    <li></li>\r\n</ul>\r\nالذكاء والقدرات الذهنية IQ<ul>\r\n    <li></li>\r\n</ul>الجبر <ul>\r\n    <li></li>\r\n</ul>الهندسة \r\n\r\n<h3>معلومات الامتحان</h3>\r\nتكون علامة اليوس من( 100) درجة موزعة على 80 سؤالاً، مقسمة إلى :\r\n<ul>\r\n    <li></li>\r\n</ul>\r\n20 سؤال هندسة <ul>\r\n    <li></li>\r\n</ul>20 سؤال جبر <ul>\r\n    <li></li>\r\n</ul>40 سؤال IQ\r\n<ul>\r\n    <li></li>\r\n</ul>تتراوح مدة الامتحان بين 100 وال120 دقيقة بنظام أسئلة مؤتمت','articles/BC8qGjwSr0A0FGBzDZ1mZb6ViZjjgJFcHI5PG2KE.jpg','exams','beginner',NULL,2,1,1,'2026-05-23 09:12:54','2026-06-11 08:36:23'),(9,'TR YÖS','tr-yos','<h3>تعريف</h3>\r\nهو امتحان مركزي موحد للطلاب الأجانب الراغبين في الدراسة في الجامعات التركية ، تعتمد نتيجته كبرى الجامعات التركية كمعيار أساسي للمفاضلة .\r\n\r\n<h3>معلومات الامتحان</h3>\r\nتكون مدة الامتحان 100 دقيقة يطبق في الاختبار نظام (الخطأ يذهب الصواب )، حيث أن كل اربع إجابات خاطئة تحذف إجابة واحدة صحيحة .<ul>\r\n    <li></li>\r\n</ul>\r\nتكون علامة الامتحان من 500 ويشمل جميع المواد <ul>\r\n    <li></li>\r\n</ul>يعقد الامتحان مرتين في السنة :<ul>\r\n    <li></li>\r\n</ul>يقام عادةً في النصف الاول من العام حوالي شهر مايو <ul>\r\n    <li></li>\r\n</ul>يقام المتحان الثاني في النصف الثاني من العام حوالي اكتوبر او نوفمبر<ul>\r\n    <li></li>\r\n</ul> يكون الامتحان صالح لمدة سنتين من تاريخ صدور الشهادة','articles/bMuInc3PaPec4h3GN8zFPqRrTFkCpO0PY3GbGnt8.jpg','exams','beginner',NULL,2,1,1,'2026-05-23 09:37:16','2026-05-23 10:20:15'),(10,'امتحان السات SAT','amthan-alsat-sat','<h3>تعريف</h3>\r\nاختبار معياري أمريكي عالمي ، يعتبر من أهم الامتحانات الذي يطلب من الطلاب الدوليين و الأتراك اللذين درسوا الثانوية في الخارج والراغبين في التقديم على التخصصات الطبية والهندسية . \r\n\r\n<h3>معلومات الامتحان</h3>\r\nمدة الامتحان ساعتين و14 دقيقة مقسمة وفق :<ul>\r\n    <li></li>\r\n</ul>\r\n64 دقيقة( انكليزي )قراءة وكتابة <ul>\r\n    <li></li>\r\n</ul>70 دقيقة رياضيات <ul>\r\n    <li></li>\r\n</ul>يكون الامتحان الكتروني بشكل كامل <ul>\r\n    <li></li>\r\n</ul>العلامة النهائية من 1600','articles/5gM7LR4WrBF7mcfKeUTphn472WgG2uwmVMIwsIor.png','exams','beginner',NULL,2,1,3,'2026-05-23 09:58:54','2026-06-11 08:36:38'),(11,'امتحان YKS','amthan-yks','<h3>تعريف</h3>\r\nهو امتحان قبول جامعي موحد في تركيا ، يطلب من الطلاب الحاصلين على الشهادة الثانوية التركية أو الطلاب الذين درسوا أي صف من المرحلة الثانوية في تركيا .\r\n\r\n<h3>أقسامه</h3>\r\nيقسم إلى ثلاث جلسات أساسية تعقد على مدار عطلة نهاية أسبوع واحدة .<ul>\r\n    <li></li>\r\n</ul>\r\nالجلسة الأولى : اختبار الكفاءة الأساسية TYT : هي جلسة إلزامية لجميع الطلاب ، تكون مدتها  165 دقيقة وتتكون من 120 سؤال ، ويجب الحصول على علامة معينة كشرط أساسي للمرور الى الجلسة الثانية .<ul>\r\n    <li></li>\r\n</ul>الجلسة الثانية : اختبار الكفاءة الميدانية AYT: يركز هذا الاختبار على التخصص الدقيق للطالب في الثانوية (علمي ،أدبي ، متكافئ ) تكون مدة الجلسة 180 دقيقة بعدد أسئلة إجمالي 160 سؤال (يجيب الطالب فقط على الاسئلة الخاصة بمساره ) .<ul>\r\n    <li></li>\r\n</ul>الجلسة الثالثة : اختبار اللغة الأجنبية DYT : هذا الاختبار مخصص للطلاب الراغبين في دخول كليات اللغات ، مدة هذا الاختبار 120 دقيقة موزعة على 80 سؤال','articles/OMaIz6jl0Lvtmk1z2AOQpombSfL95uwWUXpIzPzt.jpg','exams','beginner',NULL,2,1,0,'2026-05-23 10:20:14','2026-06-07 08:44:10'),(12,'امتحان DGS','amthan-dgs','<h3>تعريف</h3>\r\nهو اختبار تركي رسمي مخصص للطلاب الراغبين في النقل من جامعة إلى أخرى ، يشترط أن يكون تركي أو حامل للجنسية التركية .\r\n\r\n<h3>أقسامه</h3>\r\nيقسم الامتحان إلى قسمين :<ul>\r\n    <li></li>\r\n</ul>\r\n القسم الرياضي : يتألف من 60 سؤال ويركز بشكل أساسي على الرياضيات والهندسة و أسئلة المنطق .<ul>\r\n    <li></li>\r\n</ul>القسم اللغوي : يتألف من 60 سؤال ويركز على اللغة التركية فهم المقروء والقواعد .\r\n\r\n<h3>معلومات الامتحان</h3>\r\n تكون مدة الامتحان 135 دقيقة ويعقد مرة واحدة في السنة غالبا في يوليو .<ul>\r\n    <li></li>\r\n</ul>يعتمد نظام (الخطأ يذهب الصواب ) حيث أن كل 4 إجابات خاطئة تسقط إجابة صحيحة .','articles/R6wnFZfbKjjuJ1RhrVAQPHKRZ64mpT4D4nGd38ug.jpg','exams','beginner',NULL,2,1,0,'2026-05-23 10:36:05','2026-06-07 09:09:53'),(13,'الأسئلة الشائعة حول الدراسة في تركيا','lasyl-at-lshy-at-hwl-ldrs-at-fy-trky','<h3>ماهو المستوى المطلوب للغة التركية بغرض القبول؟</h3>\r\nادنى مستوى قد يطلب للقبول هو B1 و أعلى مستوى قد يطلب للقبول هو C1، ويختلف ذلك بحسب الجامعة من جامعة إلى أخرى. \r\n\r\n\r\n<h3>هل الجامعات الخاصة فيها سكن؟</h3>\r\nنعم، بعض الجامعات الخاصة فيها سكن طلابي، لكن قد تكون الأجور مرتفعة بعض الشيء.\r\n\r\n<h3>من الـأفضل الجامعات الحكومية أم الخاصة؟</h3>\r\nتعتبر الجامعات الحكومية أقوى من الجامعات الخاصة، لكن لصعوبة الشروط تعتبر الجامعات الخاصة أسهل وأضمن للطالب.\r\n\r\n<h3>الأقساط</h3>\r\nتختلف الأقساط من جامعة إلى أخرى و بإختلاف الفرع.\r\n\r\n<h3>هل الجامعات الخاصة معترف بها؟</h3>\r\nبالطبع، الجامعات الخاصة معترف بها حسب الدولة، فبعض الدول قد تحتاج إلى معادلة والبعض الأخر لا يحتاج.\r\n\r\n<h3>كم عدد سنوات الدراسة؟</h3>\r\nتكون عدد سنوات دراسة البكالوريوس لكافة الكليات 4 سنوات بما في ذلك الهندسات، أما الصيدلة وطب الأسنان فتكون 5 سنوات، والطب فيكون 6 سنوات، والمعاهد تكون مدة دراستها سنتين فقط.\r\n\r\n<h3>هل المنحة الجزئية تشمل الشنة التحضيرية؟</h3>\r\nبعض الجامعات تشمل السنة التحضيرية ضمن الأقساط المدفوعة، والبعض الأخر لا يتضمن السنة التحضيرية مع القسط.\r\n\r\n<h3>هل يمكن الدراسة باللغة الإنكليزية في الجامعات التركية؟</h3>\r\nنعم، بالتأكيد يمكن الدراسة باللغة الإنكليزية في الجامعات التركية الحكومية منها والخاصة،لكن يشترط وجود شهادة TOEFL أو IELTS.\r\n\r\n<h3>هل يحق للطالب الأجنبي العمل أثناء الدراسة؟</h3>\r\nنعم يحق للطالب العمل أثناء الدراسة.\r\n\r\n<h3>كيف يحصل الطالب على الإقامة الدراسية؟ وماهي ميزاتها؟</h3>\r\nيحصل الطالب على الإقامة الدراسية عندما يقوم بتثبيت أوراقه في الجامعة، فيحصل على ورقة öğrenci belgesi  الذي يتقدم عن طريقها بموعد للهجرة للحصول على إقامة طالب.\r\nميزاتها: \r\nالحصول على تأمين صحي.\r\nالحصول على بطاقة مواصلات طلابية.\r\nالسفر والتنقل دون الحاجة إلى إذن سفر من الهجرة.\r\nالحصول على حسابات بنكية.\r\nإمكانية الحصول على الجنسية التركية.\r\n\r\n<h3>ماهي الخدمات التي يحصل عليها الطالب في تركيا؟</h3>\r\nالتخفيضات في أغلب الأسعار، وإمكانية العمل (حسب الرغبة).\r\n\r\n<h3>ماهي الأفرع الأسرع لدخول في سوق العمل؟</h3>\r\nالمعاهد الطبية، حيث تكون مدة دراستها سنتين فقط، وعملها مطلوب في السوق التركي والحاجة الكبيرة إليها.\r\n\r\n<h3>هل يوجد سكن في الجامعات الحكومية؟ وماهي شروط التسجيل عليه؟</h3>\r\nنعم، توفر الجامعات الحكومية سكن طلابي، لكن يوجد مفاضلة يجب أن يقدم عليها الطالب، وعلى أساس النتائج إما قبول أو رفض.\r\nويقدم سكن الجامعات الحكومية بعض الخدمات:\r\nتوفير الطعام بمبلغ معين لكل وجبة.\r\nتوفير إقامة مجانية وفواتير مجانية بالكامل.\r\nتأمين جميع الحالات الطارئة مثل الإسعاف وغيرها....\r\n\r\n\r\n<h3>هل يمكن للطالب التوظف بعد التخرج؟</h3>\r\nنعم، يخضع الطالب إلى امتحان Kbss للتوظف عند الدولة، لكن شرط هذا الامتحان أن يملك الطالب الجنسية التركية.\r\nولا يمكن للطالب العمل بالوظائف الحكومية دون هذا الاختبار، لكن يستطيع الطالب العمل في الوظائف الخاصة.\r\n\r\n\r\n<h3>كم تكلفة المعيشة للطالب؟</h3>\r\nحسب رغبة الطاب، فتختلف بإختلاف السكن( حكومي، خاص، بيت مستقل)، لكن بشكل عام تكون تقريبا:\r\n100 دولار في حال كان الطالب في سكن حكومي.\r\n300,400 دولار في حال كان الطالب في بيت مستقل ( لا يشمل أجار البيت).\r\n200 دولار في حال كان الطالب في سكن طلابي خاص.\r\nأما في حال كان الطالب في سكن الجامعات الخاصة فقد تصل إلى 600,800 دولار مع تأمين الطعام والمواصلات.','articles/z87XX45XmIMLfE6wVcN7PSFQaYFQWZiMm2DMqv8J.jpg','turkey-studies','beginner',NULL,2,1,6,'2026-05-24 10:16:27','2026-06-07 09:15:14');
