INSERT INTO `universities` VALUES (1,'جامعة كارابوك','Karabük Üniversitesi','كارابوك','2007','public','https://www.karabuk.edu.tr/','universities/04K9kau7e6Utlh9jqT8JJjzfuePUTogVfLna4vEa.png','\"[\\\"test-image.jpg\\\",\\\"university-gallery\\\\/1781163974_6a2a67c6c85dd.jpeg\\\",\\\"university-gallery\\\\/1781163974_6a2a67c6d15d1.jpeg\\\",\\\"university-gallery\\\\/1781163974_6a2a67c6d27f2.jpeg\\\",\\\"university-gallery\\\\/1781163974_6a2a67c6d3ab1.jpeg\\\",\\\"university-gallery\\\\/1781163974_6a2a67c6d4c91.jpeg\\\",\\\"university-gallery\\\\/1781163974_6a2a67c6d5dda.jpeg\\\"]\"',60,NULL,'جامعة كارابوك (Karabük Üniversitesi) هي جامعة حكومية تركية بارزة تأسست عام 2007 في مدينة كارابوك، وتتميز بسرعة تطورها الأكاديمي وتركيزها القوي على الهندسة والتقنية. تضم الجامعة حوالي 16 كلية وأكثر من 50 قسماً، وتستقطب عدداً كبيراً من الطلاب الدوليين، وتوفر برامج تعليمية باللغتين التركية والإنجليزية.\r\nتعتبر جامعة كارابوك وجهة تعليمية مفضلة للطلاب الدوليين نظراً لموقعها، وتكاليفها المعقولة، والسمعة الطيبة التي اكتسبتها في البحث العلمي والتطوير المهني.','2026-05-17 07:04:28','2026-06-11 04:46:14','[\"turkish\", \"english\"]','https://www.youtube.com/embed/-a_a2T-RFcM?si=-VNbGcPd7nCNvEmQ',0.0,NULL,NULL),(2,'جامعة سينوب','Sinop Üniversitesi','سينوب','2007','public','https://www.sinop.edu.tr/','universities/rXKpe4p6RHwmbvFcr6m17WArhFjLJCYnL9Byf6TR.png','\"[\\\"university-gallery\\\\/1781104186_6a297e3a1251d.jpeg\\\",\\\"university-gallery\\\\/1781104186_6a297e3a16eab.jpeg\\\",\\\"university-gallery\\\\/1781104186_6a297e3a1747f.jpeg\\\",\\\"university-gallery\\\\/1781104186_6a297e3a17b3e.jpeg\\\",\\\"university-gallery\\\\/1781104186_6a297e3a180bf.jpeg\\\"]\"',112,NULL,'تعتبر جامعة سينوب احدى الجامعة الحكومية الواقعة في مدينة سينوب تأسست بتاريخ 29 أيار عام 2007 , وتسعى الجامعة جاهدة للحصول على المعلومات من اجل التطور التكنولوجي العلمي الاقتصادي والثقافي والاجتماعي للانسانية والدولة , وتنفيذ الانشطة والبحوث العلمية حسب المعايير العالمية , كما تهدف الى انشاء جيل مجهز مثقف بهذه المعلومات .\r\n\r\nلغة التدريس في الجامعة هي اللغة التركية والانكليزية , بلغ عدد الطلاب في الجامعة في العام الدراسي 2013 / 2014 حوالي 5371 طالب وطالبة وبلغ عدد اعضاء الهيئة التدريسية 363 عضو .\r\n\r\nتضم الجامعة 8 كليات و 2 معاهد و 2 معاهد تعليم عالي و 5 معاهد تعليم عالي مهني و 4 اقسام مرتبطة بادارة الجامعة و 5 مراكز تطبيق وبحوث .','2026-05-17 07:12:49','2026-06-10 12:09:46','[\"turkish\", \"english\"]','https://www.youtube.com/embed/EtA5WsX44uE?si=toOMK_lRVG7qsZxd',0.0,NULL,NULL),(3,'جامعة بايبورت','Bayburt','بايبورت','2008','public','https://www.bayburt.edu.tr/','universities/KnmnWOYKwVOUOK7BC897kuZk24UIxYd0aye78gIz.png','\"[\\\"university-gallery\\\\/1781094198_6a295736680c8.jpeg\\\",\\\"university-gallery\\\\/1781094198_6a2957366b552.jpeg\\\",\\\"university-gallery\\\\/1781094198_6a2957366c11b.jpeg\\\",\\\"university-gallery\\\\/1781094198_6a2957366c860.jpeg\\\",\\\"university-gallery\\\\/1781094198_6a2957366cd72.jpeg\\\",\\\"university-gallery\\\\/1781094198_6a2957366d30f.jpeg\\\"]\"',111,NULL,'تأسست جامعة بايبورت (Bayburt Üniversitesi) عام 2008 في مدينة بايبورت بشمال شرق تركيا، وهي جامعة حكومية بحثية حديثة تسعى للتميز الأكاديمي، خاصة في مجالات الهندسة والعلوم الطبيعية والتربية. تتميز الجامعة ببيئة تعليمية هادئة وآمنة، وتضم 11 كلية و6 معاهد، وتركز على جودة التعليم وتطوير المهارات، مع لغة تدريس أساسية هي التركية','2026-05-17 07:18:56','2026-06-10 09:23:18','[\"turkish\"]','https://www.youtube.com/embed/5-lZb_-wEPg?si=gvocYTRR3oVzoEwP',0.0,NULL,NULL),(4,'جامعة انقرة يلدرم بيازيد','Ankara Yıldırım Beyazıt Üniversitesi','انقرة','2010','public','https://www.aybu.edu.tr/','universities/4f5f6IvOfNYAurilV1fSAqDh8xpGNaCB4wkJdeDM.png','\"[\\\"university-gallery\\\\/1781088753_6a2941f1f173e.jpeg\\\",\\\"university-gallery\\\\/1781088754_6a2941f20685d.jpeg\\\",\\\"university-gallery\\\\/1781088754_6a2941f2077b6.jpeg\\\",\\\"university-gallery\\\\/1781088754_6a2941f208822.jpeg\\\",\\\"university-gallery\\\\/1781088754_6a2941f209769.jpeg\\\"]\"',37,NULL,'تم تأسيس جامعة انقرة يلدرم بيازيد الحكومية بفعل القانون 27648 الصادر عن البرلمان التركي بتاريخ 21 حزيران/ يونيو 2010، وبدأ نشاطها التعليمي الفعلي بتاريخ 3 تشرين الثاني/ نوفمبر 2011، وكان الهدف الرئيسي من تأسيس الجامعة هو تكوين برنامج موازي للقضايا المعاصرة ومطور للفكر “الانفتاحي” والابتعاد عن الفكر الإنغلاقي المحصور داخل حدود جغرافية محددة. على الرغم من أن جامعة انقرة يلدرم بيازيد جامعة حديثة الميلاد، إلا أنها تحتضن بداخلها أكاديميين ذو خبرة واسعة ومتراكمة وأغلبهم كان يعمل في جامعات أخرى قبل انتقالهم لجامعة انقرة يلدرم بيازيد، أيضاً على الرغم من قصر عمر يلديريم بيازيد إلا أنها تحتوي الآن على 915 دكتور أكاديمي تم استقدامهم من أوروبا والجامعات المرموقة في تركيا','2026-05-17 07:18:58','2026-06-10 08:47:23','[\"turkish\", \"english\"]','https://www.youtube.com/embed/lR05GT84SE4?si=ePUwo4a1fNKEZ3is',0.0,NULL,NULL),(5,'جامعة اغدير','Iğdır Üniversitesi','اغدير','2008','public','https://www.igdir.edu.tr/','universities/FmY9qPlhrU8YXXjwALnKXqeCADaouqkTfBY4uOfg.png','\"[\\\"university-gallery\\\\/1781082427_6a29293b1faab.jpeg\\\",\\\"university-gallery\\\\/1781082427_6a29293b2290f.jpeg\\\",\\\"university-gallery\\\\/1781082427_6a29293b22f89.jpeg\\\",\\\"university-gallery\\\\/1781082427_6a29293b23923.jpeg\\\",\\\"university-gallery\\\\/1781082427_6a29293b23eb5.jpeg\\\"]\"',108,NULL,'جامعة إغدير (Iğdır Üniversitesi) هي جامعة حكومية تركية تأسست عام 2008 في مدينة إغدير بشرق تركيا، وتتميز بموقع استراتيجي وثقافة غنية. تضم الجامعة 11 كلية و4 معاهد مهنية، وتقدم برامج دراسية حديثة بأسعار معقولة. توفر بيئة تعليمية آمنة ومتطورة، مع التركيز على البحث العلمي وتنمية المنطقة','2026-05-17 07:29:17','2026-06-10 06:07:07','[\"turkish\"]','https://www.youtube.com/embed/yon08zhWA1A?si=bqSNuBrJ11JSKJt9',0.0,NULL,NULL),(6,'جامعة كهرمان مرعش استقلال','Kahramanmaraş İstiklal Üniversitesi','كهرمان مرعش','2018','public','https://www.istiklal.edu.tr/','universities/Kaa0zcGmC8nClVdThKSS1qY2k9C876b3hcvpCsRn.png','\"[\\\"university-gallery\\\\/1781166315_6a2a70eb90a11.jpeg\\\",\\\"university-gallery\\\\/1781166315_6a2a70eb9c8eb.jpeg\\\",\\\"university-gallery\\\\/1781166315_6a2a70eb9e2a4.jpeg\\\",\\\"university-gallery\\\\/1781166315_6a2a70eb9f85a.jpeg\\\",\\\"university-gallery\\\\/1781166315_6a2a70eba0c06.jpeg\\\"]\"',NULL,NULL,'جامعة كهرمان مرعش استقلال (Kahramanmaraş İstiklal Üniversitesi) هي جامعة حكومية تركية حديثة تأسست عام 2018 في مدينة كهرمان مرعش. تهدف إلى تقديم تعليم حديث وتضم 7 كليات و4 معاهد مهنية ومراكز أبحاث، وتعتمد اللغة التركية لغة تدريس أساسية، مع بنية تحتية متطورة.\r\n توفر الجامعة مساكن طلابية قريبة من الحرم الجامعي، وتتميز بتقديم دعم للطلاب الدوليين في السكن والاندماج الثقافي.\r\nتعمل الجامعة على تعزيز شراكاتها الدولية لتوفير برامج تبادل طلابي','2026-05-17 08:25:17','2026-06-11 07:48:20','[\"turkish\", \"arabic\"]','https://www.youtube.com/embed/2YgOVLsrKy0?si=Jj_1MryRHKijSTyS',0.0,NULL,NULL),(7,'جامعة بيلجيك','Bilecik Şeyh Edebali Üniversitesi','بيلجيك','2007','public','https://www.bilecik.edu.tr/','universities/wAOD8nxTwsE9EfQ0bedvciFq60nC3XJ7IxWGecD9.png','\"[\\\"university-gallery\\\\/1781097044_6a2962547f533.jpeg\\\",\\\"university-gallery\\\\/1781097044_6a2962548506c.jpeg\\\",\\\"university-gallery\\\\/1781097044_6a29625485b44.jpeg\\\",\\\"university-gallery\\\\/1781097044_6a296254864e9.jpeg\\\",\\\"university-gallery\\\\/1781097044_6a296254871df.jpeg\\\"]\"',101,NULL,'تعتبر جامعة بيلجيك إحدى الجامعات الحكومية في مدينة بيلجيك في تركيا , تأسست جامعة بيلجيك في عام 2007 , بدأت الجامعة بتدريس الاختصاصات : معهد العلوم الاجتماعية، معهد العلوم الطبيعية، كلية العلوم والآداب، كلية الهندسة، كلية الاقتصاد والعلوم الإدارية، والمدارس المهنية الوسطى . وفي العام الدراسي 2013 – 2014 تمت الموافقة على الطلب لإنشاء كلية للعلوم الإسلامية وكلية العلوم التطبيقية بعد تعيين عدد كاف من الموظفين .. اليوم تحتوي الجامعة على 16 ألف طالب . الجامعة تعلق أهمية كبيرة على الأنشطة الاجتماعية والثقافية إلى جانب أنشطة التعليم والدراسات العلمية وتطمح الى تزويد طلابها بكافة معايير التعليم على المستوى الدولي , وزيادة مستويات الوعي الثقافي والانساني للطلبة , وهي تطمح بان تكون احدى المؤسسات المتقدمة وصاحبة الريادة في مجال البحث والتطوير العلمي','2026-05-17 08:25:42','2026-06-10 10:10:44','[\"turkish\"]','https://www.youtube.com/embed/fd96e2QAYOY?si=PtWLoNrN2DPuGH91',0.0,NULL,NULL),(8,'محمد عاكف ارسوي','Burdur Mehmet Akif Ersoy Üni.','بوردور','2006','public','https://www.mehmetakif.edu./','universities/qvzgnhfXKDqwSHVscpRcWShnEmpRAOIhmCkv2VLq.png','\"[\\\"university-gallery\\\\/1781175313_6a2a94111aa36.jpeg\\\",\\\"university-gallery\\\\/1781175313_6a2a94111f1c9.jpeg\\\",\\\"university-gallery\\\\/1781175313_6a2a94111fe97.jpeg\\\",\\\"university-gallery\\\\/1781175313_6a2a9411206a5.jpeg\\\",\\\"university-gallery\\\\/1781175313_6a2a941120bf0.jpeg\\\"]\"',93,NULL,'تأسست جامعة بايبورت (Bayburt Üniversitesi) عام 2008 في مدينة بايبورت بشمال شرق تركيا، وهي جامعة حكومية بحثية حديثة تسعى للتميز الأكاديمي، خاصة في مجالات الهندسة والعلوم الطبيعية والتربية. تتميز الجامعة ببيئة تعليمية هادئة وآمنة، وتضم 11 كلية و6 معاهد، وتركز على جودة التعليم وتطوير المهارات، مع لغة تدريس أساسية هي التركية.','2026-05-17 08:28:14','2026-06-11 07:55:13','[\"turkish\", \"english\"]','https://www.youtube.com/embed/WCXvz-6x0UY?si=ZK1KQmnUrQX8-oQG',0.0,NULL,NULL),(9,'جامعة بارتن','Bartın Üniversitesi','بارتن','2008','public','https://www.bartin.edu.t/','universities/sYC4HG04bQXrCOSXMKzcDNDE5YkGfRYC9C1iZ5Gs.png','\"[\\\"university-gallery\\\\/1781092669_6a29513d637e6.jpeg\\\",\\\"university-gallery\\\\/1781092669_6a29513d67915.jpeg\\\",\\\"university-gallery\\\\/1781092669_6a29513d67eb1.jpeg\\\",\\\"university-gallery\\\\/1781092669_6a29513d68477.jpeg\\\",\\\"university-gallery\\\\/1781092669_6a29513d68975.jpeg\\\"]\"',76,NULL,'تأسست جامعة بارتن عام 2008 كجامعة حكومية تهدف إلى تقديم تعليم عالي متميز في مدينة بارتن الواقعة شمال تركيا. تسعى الجامعة إلى تلبية احتياجات المجتمع المحلي والإقليمي من خلال توفير برامج أكاديمية متنوعة تركز على الجمع بين التعليم النظري والتطبيقي.\r\n\r\nتضم جامعة بارتن عدة كليات تشمل كلية الهندسة، كلية العلوم الإدارية والاقتصادية، كلية التربية، وكلية الآداب والفنون. تقدم الجامعة برامجها باللغة التركية وتعمل على تمكين الطلاب من تطوير مهاراتهم العملية من خلال توفير فرص تدريبية وتعاون مع المؤسسات المحلية والدولية.\r\n\r\nتركز الجامعة على البحث العلمي والابتكار من خلال مراكز الأبحاث التي تساهم في تعزيز المعرفة والتنمية المستدامة في المنطقة. كما توفر بيئة تعليمية حديثة تلبي احتياجات الطلاب وتسهم في إعدادهم لسوق العمل.\r\n\r\nتعد جامعة بارتن خيارًا مناسبًا للطلاب الذين يبحثون عن تعليم عالي في بيئة تجمع بين التقاليد الأكاديمية والتطبيق العملي، مما يساعد على تطوير قدراتهم وتأهيلهم لسوق العمل المتنوع.','2026-05-17 09:01:38','2026-06-10 09:38:54','[\"turkish\", \"english\"]','https://www.youtube.com/embed/Y4PkhEpkaKs?si=iYhaHDOEtTUoePxs',0.0,NULL,NULL),(10,'جامعة جوموش هانة','Gümüşhane Üniversitesi','جوموش هانة','2008','public','https://www.gumushane.edu.tr/','universities/PYNeJ6d98reOBqL5rjJ6uyqmIdzUWZlzPxPt5THG.png','\"[\\\"university-gallery\\\\/1781101829_6a2975050dc0d.jpeg\\\",\\\"university-gallery\\\\/1781101829_6a29750512868.jpeg\\\",\\\"university-gallery\\\\/1781101829_6a29750513040.jpeg\\\",\\\"university-gallery\\\\/1781101829_6a29750513987.jpeg\\\"]\"',130,NULL,'جامعة غوموش هانة (Gümüşhane Üniversitesi) هي جامعة حكومية تركية تأسست عام 2008 في مدينة غوموش هانة شمال تركيا، وتتميز ببيئة تعليمية هادئة وتكاليف دراسية منخفضة. تضم الجامعة عدة كليات ومعاهد، وتعتبر وجهة جذابة للطلاب الدوليين لسهولة القبول فيها (غالباً دون شرط اليوس) ولغة التدريس هي التركية مع توفر بعض التخصصات بالإنجليزية.\r\nمدينة غوموش هانة تعتبر هادئة ومعيشتها غير مكلفة للطلاب.','2026-05-17 09:14:39','2026-06-10 11:30:29','[\"turkish\", \"english\"]','https://www.youtube.com/embed/WGDkCpt8rHc?si=HPt0QfKu0GIWbdC5',0.0,NULL,NULL),(11,'جامعة هيتيت','Hitit Üniversitesi','تششوروم','2006','public','https://www.hitit.edu.tr/','universities/GMXkK2JuH3FivuC3VTuWKTnoZd0JFNxThNhDsdcH.png','\"[\\\"university-gallery\\\\/1781172029_6a2a873dd2b7d.jpeg\\\",\\\"university-gallery\\\\/1781172029_6a2a873dd5216.jpeg\\\",\\\"university-gallery\\\\/1781172029_6a2a873dd577d.jpeg\\\",\\\"university-gallery\\\\/1781172029_6a2a873dd5c7d.jpeg\\\",\\\"university-gallery\\\\/1781172029_6a2a873dd62bc.jpeg\\\"]\"',80,NULL,'تعد جامعة هيتيت (Hitit Üniversitesi) جامعة حكومية تركية بارزة تأسست عام 2006 في مدينة تشوروم (شمال وسط تركيا)، وتشتهر بتركيزها على البحث العلمي والتعاون مع الصناعة. تقدم الجامعة تعليماً عالي الجودة في 11 كلية، بما في ذلك الطب والهندسة والعلوم الصحية، وتضم أكثر من 16,000 طالب، وتعد الوحيدة في تركيا المتخصصة في مجال آلات وتكنولوجيات التصنيع.\r\nتوفر بيئة داعمة للطلاب، بالإضافة إلى مراكز تطبيقة، ومستشفى أبحاث وتطبيقات خاص بالجامعة.','2026-05-17 09:28:09','2026-06-11 07:00:29','[\"turkish\", \"english\"]','https://www.youtube.com/embed/trpe4DHdEmI?si=dmamtTgDNPx9ESat',0.0,NULL,NULL),(12,'جامعة سكاريا للعلوم التطبيقية','Sakarya Uygulamalı Bilimler Üniversitesi','سكاريا','2018','public','https://www.subu.edu.tr/','universities/k1KlyIjVyZbAzGGElt8u42CKlPKtrWK6aktdVmUO.png','\"[\\\"university-gallery\\\\/1781103695_6a297c4f16d2e.jpeg\\\",\\\"university-gallery\\\\/1781103695_6a297c4f1957a.jpeg\\\",\\\"university-gallery\\\\/1781103695_6a297c4f19a15.jpeg\\\",\\\"university-gallery\\\\/1781103695_6a297c4f19e42.jpeg\\\",\\\"university-gallery\\\\/1781103695_6a297c4f1a879.jpeg\\\"]\"',118,NULL,'تأسست جامعة سكاريا للعلوم التطبيقية عام 2018، وهي جامعة حديثة تهدف إلى تقديم تعليم عالي تطبيقي يركز على دمج المعرفة الأكاديمية مع التدريب العملي، مما يساعد في تأهيل الطلاب لسوق العمل بشكل فعّال. تقع الجامعة في مدينة سكاريا التي تُعد من المناطق الصناعية المهمة في تركيا، مما يتيح للطلاب فرصًا كبيرة للتدريب العملي والتفاعل مع القطاع الصناعي.\r\n\r\nتضم الجامعة عدة كليات ومدارس مهنية تركز على مجالات متعددة مثل الهندسة، التكنولوجيا، السياحة، والتربية. كما تُعرف الجامعة ببرامجها الدراسية التطبيقية التي تشمل التدريب المهني الميداني والتعاون الوثيق مع الشركات المحلية والدولية.\r\n\r\nتقدم جامعة سكاريا للعلوم التطبيقية برامج أكاديمية متقدمة على مستوى البكالوريوس والدراسات العليا باللغة التركية، وتهدف إلى تعزيز مهارات الطلاب العملية والتقنية من خلال برامج تدريبية مبتكرة.\r\n\r\nتُعد الجامعة وجهة مميزة للطلاب الذين يسعون للحصول على تعليم تطبيقي يربط بين النظرية والتطبيق العملي، ويعمل خريجوها في مجموعة متنوعة من القطاعات الصناعية والخدمية في تركيا وخارجها.','2026-05-17 10:16:35','2026-06-10 12:01:35','[\"turkish\"]','https://www.youtube.com/embed/-SCozhQy3hY?si=PkBhRS6_c4_uVL3O',0.0,NULL,NULL),(13,'جامعة اديامان','Adıyaman Üniversitesi','اديامان','2006','public','https://www.adiyaman.edu.tr/','universities/qScaiZQFqq0KdnOQdrHWeoVU9pGGsGTBrYg1HLWv.png','\"[\\\"university-gallery\\\\/1780924945_6a26c211cb995.jpeg\\\",\\\"university-gallery\\\\/1780924945_6a26c211d0367.jpeg\\\",\\\"university-gallery\\\\/1780924945_6a26c211d0a3b.jpeg\\\",\\\"university-gallery\\\\/1780924945_6a26c211d0fe4.jpeg\\\",\\\"university-gallery\\\\/1780924945_6a26c211d16e0.jpeg\\\"]\"',95,NULL,'جامعة أديامان (Adıyaman Üniversitesi) هي جامعة حكومية تركية تأسست عام 2006 في مدينة أديامان، وتضم 13 كلية، 3 معاهد، و6 مدارس مهنية. توفر الجامعة تعليماً لأكثر من 17 ألف طالب، وتعتمد اللغتين التركية والإنجليزية، وتحتل المرتبة 67 على مستوى تركيا. تقع على مساحة واسعة تضم 4 أحرم جامعية، وتوفر بيئة تعليمية وسكناً طلابياً داخل الحرم.','2026-05-17 10:17:34','2026-06-11 04:22:14','[\"turkish\", \"english\"]','https://www.youtube.com/embed/4wKxGf-jxjE?si=3Paz3SWA0XhOSPhm',0.0,NULL,NULL),(14,'سكاريا','Sakarya Üniversitesi','سكاريا','1992','public','https://www.sakarya.edu.tr/','universities/qH5ltxtuUsikVnSyo9jYqtn4HfNKmAoQ5Ahcxxye.png','\"[\\\"university-gallery\\\\/1781175168_6a2a93806a64d.jpeg\\\",\\\"university-gallery\\\\/1781175168_6a2a93806f66c.jpeg\\\",\\\"university-gallery\\\\/1781175168_6a2a938070eca.jpeg\\\",\\\"university-gallery\\\\/1781175168_6a2a9380718cb.jpeg\\\",\\\"university-gallery\\\\/1781175168_6a2a938072222.jpeg\\\"]\"',31,NULL,'جامعة سكاريا (Sakarya Üniversitesi) هي جامعة حكومية تركية عريقة تأسست عام 1970 كأكاديمية للهندسة، وتعد حالياً من كبرى جامعات تركيا. تقع في مدينة سكاريا (على بعد 1.5 ساعة من إسطنبول)، وتتميز بقوة برامجها الهندسية والتكنولوجية، بالإضافة إلى اعترافاتها الدولية، وهي أول جامعة حكومية في تركيا تحصل على شهادة الجودة ISO-2002','2026-05-20 04:39:08','2026-06-11 07:52:48','[\"turkish\", \"english\"]','https://www.youtube.com/embed/ijcTOGXlS-Y?si=GzvF8ji2oLP4ApRy',0.0,NULL,NULL),(15,'جامعة اولوداغ','Bursa Uludağ Üniversitesi','بورصة','1975','public','https://www.uludag.edu.tr/','universities/58sYuaZSunQMwLfMmg77EBTbwzAXLkEEKN32EWHP.png','\"[\\\"university-gallery\\\\/1781090831_6a294a0fa3296.jpeg\\\",\\\"university-gallery\\\\/1781090831_6a294a0fa90a6.jpeg\\\",\\\"university-gallery\\\\/1781090831_6a294a0fa9d96.jpeg\\\",\\\"university-gallery\\\\/1781090831_6a294a0faa5e6.jpeg\\\",\\\"university-gallery\\\\/1781090831_6a294a0faafa6.jpeg\\\",\\\"university-gallery\\\\/1781090831_6a294a0fab94b.jpeg\\\"]\"',27,NULL,'جامعة بورصة أولوداغ (Bursa Uludağ Üniversitesi) هي جامعة حكومية عريقة تأسست عام 1975 في مدينة بورصة التركية، وتعتبر من الجامعات الرائدة التي تركز على الطب، الهندسة، والعلوم الطبيعية. تضم الجامعة 15 كلية، 4 معاهد، وتصنف ضمن أفضل 30 جامعة حكومية في تركيا','2026-05-20 09:20:22','2026-06-10 08:27:11','[\"turkish\", \"english\"]','https://www.youtube.com/embed/vF9Il7F-aRI?si=BiC-j2DKbQ9stR8f',0.0,NULL,NULL),(16,'جامعة انقرة للعلوم الاجتماعية','Ankara Sosyal Bilimler Üniversitesi','انقرة','2013','public','https://www.asbu.edu.tr/','universities/4l9xJS5f6Ir5k2zNurJaNSO9vIZJP6vF0oPWwXl7.png','\"[\\\"university-gallery\\\\/1781088151_6a293f978c7bb.jpeg\\\",\\\"university-gallery\\\\/1781088151_6a293f9798077.jpeg\\\",\\\"university-gallery\\\\/1781088151_6a293f979ab75.jpeg\\\",\\\"university-gallery\\\\/1781088151_6a293f979d225.jpeg\\\",\\\"university-gallery\\\\/1781088151_6a293f97a2e34.jpeg\\\"]\"',168,NULL,'جامعة انقرة للعلوم الاجتماعية تعتبر سادس جامعة حكومية في العاصمة التركية انقرة وتم تأسيسها عام 2013 وتحتوي جامعة انقرة للعلوم الاجتماعية على 5 كليات و 5 معاهد تعليم عالي','2026-05-20 10:08:52','2026-06-10 08:48:42','[\"turkish\", \"english\"]','https://www.youtube.com/embed/crZ3aYyPu0w?si=8JcqSgVF61Wdkt9g',0.0,NULL,NULL),(17,'جامعة اسكي شهير تكنيك','Eskişehir Teknik Üniversitesi','اسكي شهير','2018','public','https://www.eskisehir.edu.tr/','universities/Ibh59pScxUWuYr3GpBgmlby2262cGvbDDGVO4jjY.png','\"[\\\"university-gallery\\\\/1781082063_6a2927cfb8e39.jpeg\\\",\\\"university-gallery\\\\/1781082063_6a2927cfbc52d.jpeg\\\",\\\"university-gallery\\\\/1781082063_6a2927cfbd0f0.jpeg\\\",\\\"university-gallery\\\\/1781082063_6a2927cfbdb29.jpeg\\\",\\\"university-gallery\\\\/1781082063_6a2927cfbe5a5.jpeg\\\",\\\"university-gallery\\\\/1781082063_6a2927cfbec15.jpeg\\\"]\"',47,NULL,'تأسست جامعة إسكي شهير التقنية في عام 2018، بعد انفصالها عن جامعة الأناضول العريقة، بهدف تقديم تعليم عالي الجودة في مجالات العلوم والهندسة والتكنولوجيا. تعد الجامعة إحدى الجامعات التقنية البارزة في تركيا، وتقع في مدينة إسكي شهير، التي تُعرف بأنها مدينة طلابية حديثة ومزدهرة.\r\n\r\nتضم جامعة إسكي شهير التقنية خمس كليات رئيسية، تشمل كلية الهندسة، كلية علوم الطيران والفضاء، كلية العمارة، وكلية العلوم الطبيعية. تركز الجامعة على تقديم برامج أكاديمية متميزة في مجالات الهندسة والتكنولوجيا والعلوم التطبيقية، مع تركيز كبير على البحث العلمي والابتكار.\r\n\r\nتقدم الجامعة برامجها الأكاديمية باللغة التركية والإنجليزية، وتحرص على دمج التعليم النظري بالتطبيق العملي من خلال مختبراتها المتقدمة ومراكزها البحثية المتخصصة. كما ترتبط الجامعة بشكل وثيق مع الصناعات المحلية والدولية، مما يتيح للطلاب فرصًا تدريبية وبحثية ممتازة.\r\n\r\nتعد جامعة إسكي شهير التقنية خيارًا مثاليًا للطلاب الذين يتطلعون إلى الحصول على تعليم تقني عالي الجودة والمشاركة في البحث العلمي والتطوير التكنولوجي في بيئة أكاديمية متقدمة.','2026-05-20 10:22:55','2026-06-10 06:01:03','[\"turkish\", \"english\"]','https://www.youtube.com/embed/VHMQgXDtpao?si=U0TM8RbPPbmkWPxN',0.0,NULL,NULL),(18,'جامعة غبزة تكنيك','Gebze Teknik Üniversitesi','كوجالي','1992','public','https://www.gtu.edu.t/','universities/N4h1ceCgD3QmGknCXYAyPcVhTxDHq9RFT9MAfXMD.png','\"[\\\"university-gallery\\\\/1781161596_6a2a5e7c1324f.jpeg\\\",\\\"university-gallery\\\\/1781161596_6a2a5e7c1d527.jpeg\\\",\\\"university-gallery\\\\/1781161596_6a2a5e7c1e70b.jpeg\\\",\\\"university-gallery\\\\/1781161596_6a2a5e7c1f8fe.jpeg\\\",\\\"university-gallery\\\\/1781161596_6a2a5e7c20ba0.jpeg\\\"]\"',12,NULL,'جامعة غبزة التقنية، المعروفة سابقًا باسم معهد غبزة للتكنولوجيا، هي واحدة من معهدين للتكنولوجيا في تركيا، والآخر هو معهد إزمير للتكنولوجيا. تقع الجامعة في غبزة، إحدى أكثر المناطق الصناعية في منطقة مرمرة، وتركز الجامعة على الدراسات الجامعية والدراسات العليا بالإضافة إلى الأنشطة البحثية.','2026-05-20 10:28:23','2026-06-11 04:06:36','[\"turkish\", \"english\"]','https://www.youtube.com/embed/fFL9xqF0T28?si=NMx_-OP4ISRSAKy4',0.0,NULL,NULL),(19,'جامعة بندرما 17 ايلول','Bandırma Onyedi Eylül Üniversitesi','بالك اسير','2015','public','https://www.bandirma.edu.tr/','universities/eHRW3qmo4cD30AlPsvzGozlt9lkqd72XVcI8KwdK.png','\"[\\\"university-gallery\\\\/1781094734_6a29594e120b1.jpeg\\\",\\\"university-gallery\\\\/1781094734_6a29594e15358.jpeg\\\",\\\"university-gallery\\\\/1781094734_6a29594e159ae.jpeg\\\",\\\"university-gallery\\\\/1781094734_6a29594e15ed4.jpeg\\\",\\\"university-gallery\\\\/1781094734_6a29594e1644b.jpeg\\\",\\\"university-gallery\\\\/1781094734_6a29594e169e8.jpeg\\\"]\"',156,NULL,'جامعة باندرما 17 أيلول (Bandırma Onyedi Eylül Üniversitesi) هي جامعة حكومية تركية حديثة تأسست عام 2015 في مدينة باليكسير، وتتميز بتركيزها على البحوث العلمية والتدويل. تضم الجامعة 12 كلية، 4 معاهد، و9 معاهد مهنية، وتقدم تعليماً باللغتين التركية والإنجليزية مع فرص تبادل طلابي ضمن برنامج Erasmus','2026-05-20 10:51:37','2026-06-10 09:32:14','[\"turkish\", \"english\"]','https://www.youtube.com/embed/cpUyRB2jtiA?si=H8Maw0jFq8No7dxx',0.0,NULL,NULL),(20,'جامعة موغلا صدقي كوتشمان','Muğla Sıtkı Koçman Üniversitesi','موغلا','1992','public','https://www.mu.edu.tr/','universities/J61r5b1WJz0oh9AqqKzbpPXKbKUe3jNguIj9XjPV.png','\"[\\\"university-gallery\\\\/1781170448_6a2a811028299.jpeg\\\",\\\"university-gallery\\\\/1781170448_6a2a81102d3d0.jpeg\\\",\\\"university-gallery\\\\/1781170448_6a2a81102da17.jpeg\\\",\\\"university-gallery\\\\/1781170448_6a2a81102e203.jpeg\\\",\\\"university-gallery\\\\/1781170448_6a2a81102ec7e.jpeg\\\"]\"',58,NULL,'جامعة موغلا هي مؤسسة تعليمية مرموقة تقع في مدينة موغلا التركية، وتتميز بتقديم مجموعة واسعة من البرامج الأكاديمية التي تلبي احتياجات وتطلعات الطلاب المحليين والدوليين. تأسست جامعة موغلا لتكون مركزًا للتعليم والبحث العلمي، وتضم العديد من الكليات في مختلف التخصصات مثل الهندسة، الطب، العلوم الإنسانية والاجتماعية، بالإضافة إلى كليات العلوم التطبيقية.\r\n\r\nتلتزم جامعة موغلا بتوفير بيئة تعليمية متطورة، مع التركيز على الابتكار والتطوير المستمر. كما تعمل الجامعة على تعزيز العلاقات الدولية من خلال شراكات مع مؤسسات أكاديمية عالمية، مما يفتح آفاقًا واسعة أمام طلابها للمشاركة في برامج تبادل ثقافي وأكاديمي.\r\n\r\nلجامعة موغلا دور فعال في تنمية المجتمع المحلي من خلال مشاريع بحثية تهدف إلى حل المشكلات المحلية وتعزيز التنمية المستدامة. توفر الجامعة أيضًا العديد من الفرص لطلابها للمشاركة في الأنشطة الطلابية المتنوعة التي تساهم في صقل شخصياتهم وبناء مهاراتهم القيادية.\r\n\r\nباختصار، جامعة موغلا تعد بوابة للتعليم العالي المتميز في تركيا، وهي تقدم بيئة أكاديمية محفزة تجمع بين التقاليد العلمية العريقة والمناهج التعليمية المبتكرة.','2026-05-20 10:52:22','2026-06-11 06:34:08','[\"turkish\", \"english\", \"german\"]','https://www.youtube.com/embed/IGUlH1eRruM?si=bz3qK0XxjZNinT1T',0.0,NULL,NULL),(21,'جامعة نيغدة عمر خالص ديمير','Niğde Ömer Halisdemir Üniversitesi','نيغدة','1992','public','https://www.ohu.edu.tr/','universities/t56wzxWxe4a62R326WLVEpcQlMIYTYbyE69SVA7d.png','\"[\\\"university-gallery\\\\/1781171349_6a2a84951d724.jpeg\\\",\\\"university-gallery\\\\/1781171349_6a2a849520387.jpeg\\\",\\\"university-gallery\\\\/1781171349_6a2a8495208b4.jpeg\\\",\\\"university-gallery\\\\/1781171349_6a2a849520fc1.jpeg\\\"]\"',67,NULL,'تعد جامعة نيغدة عمر خالص ديمير احدى الجامعات الحكومية التركية الموجودة في مدينة نيغدة الواقعة في الوسط من هضبة الاناضول وهي جزء من منطقة كابادوكيا السياحية الشهيرة وهي منطقة غنية بالمواصلات البرية والسكك الحديدية .\r\n\r\nتأسست جامعة نيغدة عمر خالص ديمير في 3 تموز عام 1992 ويشغل منصب رئيس الجامعة السيد البروفسور الدكتور عدنان جرور ومساعديه كلا من السادة الدكتور البروفسور محمد تشنير والدكتور البروفسور مراد اين والدكتور البروفسور مصطفى بايراق .\r\n\r\nتضم جامعة نيغدة عمر خالص ديمير حاليا في هيكلها التنظيمي 7 كليات و 3 معاهد و 3 معاهد تعليم عالي و 6 معاهد تدريب مهني وكذلك تضم الجامعة 844 اكاديمي و 535 موظف اداري واكثر من 24800 الف طالب وطالبة .','2026-05-20 11:26:32','2026-06-11 06:49:09','[\"turkish\", \"english\"]','https://www.youtube.com/embed/dnwf8fFn7lM?si=cKicEJCgkgKIAbUr',0.0,NULL,NULL),(22,'جامعة عبد الله غول','Abdullah Gül Üniversitesi','قيصري','2010','public','https://w3.agu.edu.tr/','universities/pz2hEbtNlNWYq5HGoHuEDxC7ZTC3Hv7EM5Cu8wp3.png','\"[\\\"university-gallery\\\\/1781104995_6a298163bd408.jpeg\\\",\\\"university-gallery\\\\/1781104995_6a298163c35e0.jpeg\\\",\\\"university-gallery\\\\/1781104995_6a298163c3f06.jpeg\\\",\\\"university-gallery\\\\/1781104995_6a298163c45ce.jpeg\\\"]\"',50,NULL,'جامعة عبد الله غول (Abdullah Gül University - AGU) هي جامعة حكومية تركية رائدة تأسست عام 2010 في مدينة قيصري، وتتميز بكونها \"جامعة من الجيل الجديد\" تركز على البحث العلمي والتدريس باللغة الإنجليزية بالكامل (100%)، وتدعمها أوقاف خاصة. تحظى الجامعة بسمعة أكاديمية ممتازة وتصنيفات دولية عالية بفضل نهجها الابتكاري','2026-05-20 11:34:43','2026-06-10 12:23:15','[\"turkish\", \"english\"]','https://www.youtube.com/embed/cMAaW6YR9uY?si=5O8z2B01dvkkPgW_',0.0,NULL,NULL),(23,'جامعة توكات غازي عثمان باشا','Tokat Gaziosmanpaşa Üniversitesi','توكات','1992','public','https://www.gop.edu.tr/','universities/TINLJX3Gvl4zpEj3Rut2NOriVoeQgm0yA9xKvoE2.png','\"[\\\"university-gallery\\\\/1781100748_6a2970cc4b5af.jpeg\\\",\\\"university-gallery\\\\/1781100748_6a2970cc50cb0.jpeg\\\",\\\"university-gallery\\\\/1781100748_6a2970cc512ae.jpeg\\\",\\\"university-gallery\\\\/1781100748_6a2970cc5171d.jpeg\\\",\\\"university-gallery\\\\/1781100748_6a2970cc51af3.jpeg\\\"]\"',84,NULL,'تأسست جامعة توكات غازي عثمان باشا (Tokat Gaziosmanpaşa Üniversitesi) عام 1992 في مدينة توكات التركية كجامعة حكومية رائدة، وتضم أكثر من 30 ألف طالب في تخصصات متنوعة كالهندسة، الطب، والعلوم الإنسانية. تقع في منطقة \"تاشليشفتليك\" (Taşlıçiftlik) على بعد 9 كم من وسط المدينة، وتتميز ببيئة بحثية نشطة وتكلفة دراسية معقولة','2026-05-20 12:16:25','2026-06-12 06:05:41','[\"turkish\", \"english\"]','https://www.youtube.com/embed/PJQN00C7jYM?si=iQJH4wUcU2R83FD5',0.0,NULL,NULL),(24,'جامعة أضنة للعلوم والتكنولوجيا','Adana Alparslan Türkeş Bilim Ve Teknoloji Üniversitesi','اضنة','2011','public','https://www.atu.edu.tr/','universities/Y4hpUA5oJakEP2sDyoQLLFBVfS2OZTMLAJJObbHk.png','\"[\\\"university-gallery\\\\/1780915818_6a269e6a56b99.jpeg\\\",\\\"university-gallery\\\\/1780915818_6a269e6a5f830.jpeg\\\",\\\"university-gallery\\\\/1780915818_6a269e6a60cd8.jpeg\\\",\\\"university-gallery\\\\/1780915818_6a269e6a61e39.jpeg\\\",\\\"university-gallery\\\\/1780915818_6a269e6a63111.jpeg\\\"]\"',75,NULL,'جامعة أضنة ألب أرسلان توركش للعلوم والتكنولوجيا (Adana Alparslan Türkeş Science and Technology University - ATU) هي جامعة حكومية تركية رائدة تأسست عام 2011 في مدينة أضنة، وتركز على مجالات الهندسة، التكنولوجيا، والعلوم الطبيعية. تتميز ببرامجها باللغة الإنجليزية، بنيتها التحتية الحديثة، وتهدف إلى إعداد كفاءات علمية مبتكرة.','2026-05-21 03:19:14','2026-06-08 07:50:18','[\"turkish\", \"english\"]','https://www.youtube.com/embed/Uy6BUwnKsqY?si=rjUxhRAmHqervtK_',0.0,NULL,NULL),(25,'جامعة افيون للعلوم الصحية','Afyonkarahisar Sağlık Bilimleri Üniversitesi','افيون','2018','public','https://www.afsu.edu.tr/','universities/bfKayNYw9wZCpjVuLprH4vF7lnDTMoCF6ngkCYTr.png','\"[\\\"university-gallery\\\\/1781083737_6a292e5903dfe.jpeg\\\",\\\"university-gallery\\\\/1781083737_6a292e590f999.jpeg\\\",\\\"university-gallery\\\\/1781083737_6a292e591079c.jpeg\\\",\\\"university-gallery\\\\/1781083737_6a292e5911042.jpeg\\\"]\"',159,NULL,'تأسست جامعة أفيون للعلوم الصحية (Afyonkarahisar Sağlık Bilimleri Üniversitesi - AFSÜ) عام 2018 