0.0,NULL,NULL),(163,'جامعة انطاليا بيليك','Antalya Belek Üniversitesi','انطاليا','2020','private','https://belek.edu.tr/','universities/LwjEOyYf8PXB39gCHhG40ID4bo8BmCkKJ8zw0bzn.png','\"[\\\"university-gallery\\\\/1781087268_6a293c2401cf6.jpeg\\\",\\\"university-gallery\\\\/1781087268_6a293c240a146.jpeg\\\",\\\"university-gallery\\\\/1781087268_6a293c240aee3.jpeg\\\",\\\"university-gallery\\\\/1781087268_6a293c240c0b7.jpeg\\\"]\"',188,NULL,'تسعى جامعة أنطاليا بيليك منذ تأسيسها إلى تأهيل خريجين على مستوى عالٍ من الكفاءة المهنية والأكاديمية، يكونون قادرين على مواجهة تحديات سوق العمل وصعوباته. تتمحور رؤية الجامعة حول تطوير خطط تعليمية تتماشى مع أحدث الأساليب التربوية الدولية، وتأهيل الطلاب وتحسين مهاراتهم العلمية والبحثية. تلتزم الجامعة بدمج التعليم النظري مع التطبيق العملي، خاصةً في تخصصات السياحة وطب الأسنان والهندسة، مستفيدةً من بيئتها الفريدة في المنطقة السياحية.','2026-06-06 07:28:17','2026-06-10 11:06:24','[\"turkish\", \"english\"]','https://www.youtube.com/embed/MRSCo8uuSxY?si=uxapHvWIihH7115_',0.0,NULL,NULL),(164,'جامعة اسطنبول اطلس','Istanbul Atlas Üniversitesi','اسطنبول','2018','private','https://www.atlas.edu.tr/','universities/6aczm3L7YJ5slXYz6pnkXkwvQ5V6jJllZOkvSEuX.png','\"[\\\"university-gallery\\\\/1780927440_6a26cbd017430.webp\\\",\\\"university-gallery\\\\/1780927440_6a26cbd01c76a.webp\\\",\\\"university-gallery\\\\/1780927440_6a26cbd01d0ff.webp\\\",\\\"university-gallery\\\\/1780927440_6a26cbd01da16.webp\\\",\\\"university-gallery\\\\/1780927440_6a26cbd01e425.webp\\\",\\\"university-gallery\\\\/1780927440_6a26cbd01ee29.webp\\\"]\"',NULL,NULL,'تعدّ جامعة اطلس من بين الجامعات التي تهدف إلى إنتاج المعرفة العلمية والإستفادة منها في خدمة المجتمع، ولتحقيق هذا الهدف، تضم الجامعة خمس كليات ومعهد تعليم عالي وكلية تدريس عليا تتنوع تخصصاتها.\r\n\r\nتهدف كلية الطب إلى إجراء الأبحاث العلمية في مجال الصحة وتأهيل المهنيين الصحيين المؤهلين. وتستهدف كلية طب الأسنان ومركز البحث والتطبيق في نفس الوقت إجراء الأبحاث العلمية في مجال الصحة الفموية وتعليم الطلاب المهارات النظرية والعملية','2026-06-06 07:51:39','2026-06-12 08:41:02','[\"turkish\", \"english\"]','https://www.youtube.com/embed/czYTfZu1OZk?si=Le1fVPtk-8fSDCY6',0.0,NULL,NULL),(165,'جامعة باشكينت','Başkent Üniversitesi','انقرة','1994','private','https://baskent.edu.tr/','universities/x1EOJEekkqQw3iSL1XH0hst6OkV8H4jqZwPKyK0e.png','\"[\\\"university-gallery\\\\/1781092975_6a29526fd5ba4.jpeg\\\",\\\"university-gallery\\\\/1781092975_6a29526fda42a.jpeg\\\",\\\"university-gallery\\\\/1781092975_6a29526fdab6b.jpeg\\\",\\\"university-gallery\\\\/1781092975_6a29526fdb292.jpeg\\\",\\\"university-gallery\\\\/1781092975_6a29526fdb941.jpeg\\\"]\"',53,NULL,'تأسست جامعة باشكينت (Başkent Üniversitesi) في العاصمة التركية أنقرة في 13 يناير 1994 على يد البروفيسور الدكتور محمد هابرال، لتكون أوّل جامعة خاصة في تركيا متخصصة في تدريس العلوم الصحية. تأسّست بالتعاون بين المؤسسة التركية لزراعة الأعضاء وعلاج الحروق (التي أنشأها هابرال عام 1980) ومؤسسة هابرال للتعليم.','2026-06-06 07:53:27','2026-06-11 03:57:47','[\"turkish\", \"english\"]','https://www.youtube.com/embed/SolQ-vMviHI?si=kQX7-BZBbzm9YHq8',0.0,NULL,NULL),(166,'جامعة توب للاقتصاد والتكنولوجيا','Tobb Ekonomi Ve Teknoloji Üniversitesi','انقرة','2003','private','https://etu.edu.tr/','universities/XOBvlWGwNJQQMw715oXfpguCT2LZUFp8Na3AGnWs.png','\"[\\\"university-gallery\\\\/1781100189_6a296e9d2cae9.jpeg\\\",\\\"university-gallery\\\\/1781100189_6a296e9d2fe36.jpeg\\\",\\\"university-gallery\\\\/1781100189_6a296e9d30316.jpeg\\\",\\\"university-gallery\\\\/1781100189_6a296e9d3077e.jpeg\\\",\\\"university-gallery\\\\/1781100189_6a296e9d30b8e.jpeg\\\"]\"',49,NULL,'تأسست جامعة TOBB للاقتصاد والتكنولوجيا (TOBB Ekonomi ve Teknoloji Üniversitesi - TOBB ETÜ) في العاصمة التركية أنقرة عام 2003 بمبادرة من مؤسسة الغرف والبورصات التركية للتعليم والثقافة (TOBEV) التابعة لاتحاد الغرف والبورصات التركية، أكبر منظمة تمثل القطاع الخاص في تركيا.','2026-06-06 07:55:35','2026-06-10 11:03:09','[\"english\"]','https://www.youtube.com/embed/ZCUOR92Cx8E?si=LW-HiedUzL3AsmoL',0.0,NULL,NULL),(167,'جامعة الانيا حمد الله امين باشا','Alanya Hamdullah Emin Paşa Üniversitesi','انطاليا','2015','private','https://ahep.edu.tr/','universities/NfyOUP4P5oEj3JotvvQ1tb0ntThMCfJqtAp95DXP.png','\"[\\\"university-gallery\\\\/1781084393_6a2930e9550ec.jpeg\\\",\\\"university-gallery\\\\/1781084393_6a2930e9603d3.jpeg\\\",\\\"university-gallery\\\\/1781084393_6a2930e9634af.jpeg\\\",\\\"university-gallery\\\\/1781084393_6a2930e963d8f.jpeg\\\",\\\"university-gallery\\\\/1781084393_6a2930e964645.jpeg\\\"]\"',185,NULL,'تأسست جامعة ألانيا حمد الله أمين باشا (Alanya Hamdullah Emin Paşa Üniversitesi - AHEP) في مدينة ألانيا التابعة لأنطاليا جنوب تركيا في 3 مارس 2011 بمبادرة من مؤسسة حمد الله أمين باشا، لتكون أوّل وأهم جامعة خاصة في إقليم ألانيا.','2026-06-06 07:59:47','2026-06-11 04:36:26','[\"turkish\", \"english\"]','https://www.youtube.com/embed/zJbxuEg3QeI?si=QyU7mx_UdEQMgMNn',0.0,NULL,NULL),(168,'جامعة التن باش','Altınbaş Üniversitesi','اسطنبول','2008','private','https://www.altinbas.edu.tr/','universities/wclsF7tPjWJ2C2WrvteTkOjF58q0TQSmyzGSN9QG.png','\"[\\\"university-gallery\\\\/1780928600_6a26d058eaa6b.webp\\\",\\\"university-gallery\\\\/1780928600_6a26d058f1d34.webp\\\",\\\"university-gallery\\\\/1780928600_6a26d058f2d29.webp\\\",\\\"university-gallery\\\\/1780928600_6a26d058f3dba.webp\\\",\\\"university-gallery\\\\/1780928601_6a26d05900c94.webp\\\",\\\"university-gallery\\\\/1780928601_6a26d05901c0b.webp\\\"]\"',114,NULL,'تأسست جامعة التن باش (Altınbaş Üniversitesi) في مدينة اسطنبول عام 2008 تحت اسم \"جامعة اسطنبول كمر بورغاز\" بمبادرة من مؤسسة محمد التن باش للتعليم والثقافة، وغُيّر اسمها عام 2017 إلى الاسم الحالي. أُسّست الجامعة بناءً على وصية رجل الأعمال الراحل محمد التن باش الذي طالما شدّد على أهمية \"الاستثمار في التعليم\".','2026-06-06 08:23:46','2026-06-12 06:06:20','[\"turkish\", \"english\"]','https://www.youtube.com/embed/1KXI8gJSElI?si=FChyw_HpBmFQF5G3',0.0,NULL,NULL),(169,'جامعة تشانكيا','Çankaya Üniversitesi','انقرة','1997','private','https://cankaya.edu.tr/','universities/BEX7rVNoYtcuajX0z2iIHv1ZDp772ftvRLVCzNde.png','\"[\\\"university-gallery\\\\/1781099696_6a296cb0c7801.jpeg\\\",\\\"university-gallery\\\\/1781099696_6a296cb0caf9f.jpeg\\\",\\\"university-gallery\\\\/1781099696_6a296cb0cb6cb.jpeg\\\",\\\"university-gallery\\\\/1781099696_6a296cb0cbbd8.jpeg\\\",\\\"university-gallery\\\\/1781099696_6a296cb0cc2a7.jpeg\\\"]\"',NULL,NULL,'تأسست جامعة تشانكيا (Çankaya Üniversitesi) في العاصمة التركية أنقرة في 9 يوليو 1997 بمبادرة من مؤسسة سيتكي ألب للتعليم (Sıtkı Alp Eğitim Vakfı)، وانطلقت بالنشاط الأكاديمي في فصل خريف عام 1997. أسسها رجل التعليم سيتكي ألب بالبناء على إرثه التعليمي السابق متمثلًا بمدرسة آري الثانوية (Arı Koleji)، وافتُتحت الجامعة رسميًا على يد الرئيس التركي الأسبق سليمان ديميرل. تُعدّ تشانكيا من أعرق الجامعات الخاصة في أنقرة، وتشتهر بقوة كلياتها التطبيقية والإنسانية. تمتلك الجامعة 5 كليات تضمّ 21 قسمًا، ومعهدَين للدراسات العليا يقدّمان 17 برنامج ماجستير و6 برامج دكتوراه، إضافة إلى مدرستين مهنيتين ومدرسة لغة إنكليزية تحضيرية. تشمل كلياتها: العمارة (عمارة، تصميم صناعي، عمارة داخلية، تخطيط حضري وإقليمي)، والآداب والعلوم (لغة وأدب إنكليزي، رياضيات، ترجمة، علم نفس)، والعلوم الاقتصادية والإدارية، والقانون، والهندسة. تُعدّ تشانكيا وجهة جذابة للطلاب الدوليين والعرب الراغبين في الدراسة في عاصمة تركيا في جامعة عريقة بأسعار معقولة.','2026-06-06 10:01:47','2026-06-11 05:22:26','[\"turkish\", \"english\"]','https://www.youtube.com/embed/DLqHI36wJEA?si=8sat5to-oK2l_VtW',0.0,NULL,NULL),(170,'جامعة صباح الدين زعيم','İstanbul Sabahattin Zaim Üniversitesi','اسطنبول','2010','private','https://www.izu.edu.tr/','universities/41TmNWJ9LYjESwpUZReSKeP3GBjnid4zIm21IDOO.png','\"[\\\"university-gallery\\\\/1781104433_6a297f31540e6.webp\\\",\\\"university-gallery\\\\/1781104433_6a297f3158aa0.webp\\\",\\\"university-gallery\\\\/1781104433_6a297f3159432.webp\\\",\\\"university-gallery\\\\/1781104433_6a297f3159b8c.webp\\\",\\\"university-gallery\\\\/1781104433_6a297f315a55c.webp\\\"]\"',115,NULL,'تُعد جامعة إسطنبول صباح الدين زعيم (İstanbul Sabahattin Zaim Üniversitesi) من الجامعات الخاصة الرائدة في تركيا، تأسست عام 2010 على يد وقف نشر العلم (İlim Yayma Vakfı). تركز الجامعة على تقديم تعليم متميز يجمع بين المعرفة النظرية والتطبيق العملي، بهدف تأهيل الطلاب لسوق العمل المحلي والدولي.','2026-06-06 10:15:09','2026-06-11 05:37:00','[\"turkish\", \"english\", \"arabic\"]','https://www.youtube.com/embed/pFLUg8i2F7A?si=iucpXBYU-9Lh6NCZ',0.0,NULL,NULL),(171,'جامعة ازمير للاقتصاد','İzmir Ekonomi Üniversitesi','ازمير','2001','private','https://ieu.edu.tr/','universities/K2uxifknEW3Kt4NsD87nCeh8HrLSPa8WmrO0OGjP.png','\"[\\\"university-gallery\\\\/1781078110_6a29185e9728e.jpeg\\\",\\\"university-gallery\\\\/1781078110_6a29185e9be27.jpeg\\\",\\\"university-gallery\\\\/1781078110_6a29185e9c984.jpeg\\\",\\\"university-gallery\\\\/1781078110_6a29185e9d20f.jpeg\\\",\\\"university-gallery\\\\/1781078110_6a29185e9da29.jpeg\\\",\\\"university-gallery\\\\/1781078110_6a29185e9e054.jpeg\\\"]\"',98,NULL,'تأسست جامعة إزمير للاقتصاد (İzmir Ekonomi Üniversitesi - IEU) في مدينة إزمير غرب تركيا في 14 أبريل 2001، لتكون أوّل جامعة خاصة في منطقة بحر إيجة. أسستها مؤسسة الرعاية الاجتماعية لغرفة تجارة إزمير (Izmir Chamber of Commerce Social Welfare Foundation) التي أنشئت عام 1988 لخدمة قطاع التعليم.','2026-06-06 10:16:58','2026-06-10 04:55:10','[\"english\"]','https://www.youtube.com/embed/L_1EB_c5Epo?si=j7KCpm3eTUTzZDXL',0.0,NULL,NULL),(173,'جامعة بيكنت','Beykent Üniversitesi','اسطنبول','1997','private','https://www.beykent.edu.tr/','universities/8DctvxxP2FiGqRHFLr7QiV1yasURDh2qEah49oXJ.png','\"[\\\"university-gallery\\\\/1780929927_6a26d5878c32c.webp\\\",\\\"university-gallery\\\\/1780929927_6a26d58793443.webp\\\",\\\"university-gallery\\\\/1780929927_6a26d58794684.webp\\\",\\\"university-gallery\\\\/1780929927_6a26d5879564b.webp\\\"]\"',167,NULL,'تُعد جامعة بيكنت من الجامعات الخاصة المتميزة في تركيا، حيث تأسست عام 1997 في إسطنبول على يد آدم تشيليك. تركز الجامعة على توفير تعليم متكامل يجمع بين المعرفة النظرية والتطبيق العملي، بهدف تأهيل الطلاب لسوق العمل المحلي والدولي.','2026-06-06 10:53:00','2026-06-10 05:53:28','[\"turkish\", \"english\", \"russian\", \"russian\", \"russian\", \"russian\", \"russian\"]','https://www.youtube.com/embed/6lBiFiXBGNI?si=yQ_H0Qm3vjl5GKNf',0.0,NULL,NULL),(174,'جامعة قونيا للاغذية والزراعة','Konya Gıda Ve Tarım Üniversitesi','قونيا','2013','private','https://gidatarim.edu.tr/','universities/M1Wa1EKWNeJlcn21HfpT7NRR9neLBKuetMyhtykx.png','\"[\\\"university-gallery\\\\/1781163010_6a2a64026319f.jpeg\\\",\\\"university-gallery\\\\/1781163010_6a2a640265ed6.jpeg\\\",\\\"university-gallery\\\\/1781163010_6a2a640266557.jpeg\\\",\\\"university-gallery\\\\/1781163010_6a2a640266b0c.jpeg\\\"]\"',106,NULL,'تأسست جامعة قونيا للأغذية والزراعة (Konya Gıda ve Tarım Üniversitesi) في مدينة قونيا وسط تركيا عام 2013 بمبادرة من مؤسسة بارتك (BARTEK) للبحث العلمي والتعليم والثقافة، وتُعدّ أوّل جامعة موضوعية متخصصة في الأغذية والزراعة في تركيا.','2026-06-06 10:56:08','2026-06-11 06:17:32','[\"turkish\", \"english\"]','https://www.youtube.com/embed/M3vsQCi9AbI?si=26QRkPZSvhNQu9Je',0.0,NULL,NULL),(175,'جامعة كابادوكيا','Kapadokya Üniversitesi','نيفشهير','2005','private','https://www.kapadokya.edu.tr/','universities/8uvemC5zN9IA9lx3qHgZt5RsGuq1xzIoviWsppnC.png','\"[\\\"university-gallery\\\\/1780930519_6a26d7d7cc02d.webp\\\",\\\"university-gallery\\\\/1780930519_6a26d7d7d3724.webp\\\",\\\"university-gallery\\\\/1780930519_6a26d7d7d4c5e.webp\\\",\\\"university-gallery\\\\/1780930519_6a26d7d7d5dc6.webp\\\",\\\"university-gallery\\\\/1780930519_6a26d7d7d6cbe.webp\\\",\\\"university-gallery\\\\/1780930519_6a26d7d7d7eaf.webp\\\"]\"',175,NULL,'تأسست جامعة كابادوكيا (Kapadokya Üniversitesi) في منطقة كابادوكيا التاريخية وسط تركيا، وكانت تُعرف سابقًا باسم \"مدرسة كابادوكيا المهنية\" (KMYO) حين أُنشئت عام 2005 بمبادرة من مؤسسة إلكي للتعليم والصحة، ثم رُفعت إلى مرتبة جامعة في عام 2017. تقع الجامعة في موقع فريد ضمن منطقة كابادوكيا المدرجة على قائمة التراث العالمي لليونسكو، الشهيرة بمداخنها الجنية الصخرية ومناطيد الهواء الساخن وكنائسها التاريخية. تمتلك الجامعة حرمَين رئيسيَّين: حرم مصطفى باشا في محافظة نَوْشهير (قلب كابادوكيا)، وحرم بَنديك في اسطنبول قرب مطار صبيحة كوكتشن.','2026-06-06 11:19:43','2026-06-12 08:03:04','[\"turkish\", \"english\"]','https://www.youtube.com/embed/SJVUDxROf4U?si=kqyEjAoqEjgwyF6k',0.0,NULL,NULL),(176,'جامعة بيري رئيس','Piri Reis Üniversitesi','اسطنبول','2008','private','https://pirireis.edu.tr/','universities/nWbOGYRLYANhhIBAAbFBPaML5k95UQjy8jP0raA3.png','\"[\\\"university-gallery\\\\/1781096741_6a2961252cf66.jpeg\\\",\\\"university-gallery\\\\/1781096741_6a296125318c6.jpeg\\\",\\\"university-gallery\\\\/1781096741_6a29612531ec1.jpeg\\\",\\\"university-gallery\\\\/1781096741_6a29612532475.jpeg\\\",\\\"university-gallery\\\\/1781096741_6a29612532966.jpeg\\\"]\"',138,NULL,'تأسست جامعة بيري رئيس (Pîrî Reis Üniversitesi) في مدينة اسطنبول عام 2008 بمبادرة من المؤسسة التركية للتعليم البحري، لتكون أوّل جامعة بحرية متخصصة في تركيا. سُمّيت الجامعة تيمنًا بالأميرال البحري ورسام الخرائط العثماني الشهير بيري رئيس (1470–1554) الذي يُعدّ من أبرز الشخصيات في تاريخ الملاحة العالمية.','2026-06-06 11:22:48','2026-06-11 08:25:56','[\"turkish\", \"english\"]','https://www.youtube.com/embed/oKcQWCtha58?si=pcyGlFI2VKKq6h2i',0.0,NULL,NULL),(177,'جامعة دوغوش','Doğuş Üniversitesi','اسطنبول','1997','private','https://dogus.edu.tr/','universities/qd6HnuJeJVSptyBW1V3v0IJYlO3rIY7a02mzQM0I.png','\"[\\\"university-gallery\\\\/1781102624_6a2978205445f.jpeg\\\",\\\"university-gallery\\\\/1781102624_6a2978205857a.jpeg\\\",\\\"university-gallery\\\\/1781102624_6a29782058fd5.jpeg\\\",\\\"university-gallery\\\\/1781102624_6a29782059aad.jpeg\\\",\\\"university-gallery\\\\/1781102624_6a2978205bb39.jpeg\\\"]\"',164,NULL,'تأسست جامعة دوغوش (Doğuş Üniversitesi) في مدينة اسطنبول عام 1995 بمبادرة من مؤسسة دوغوش للتعليم، وانطلقت بالنشاط الأكاديمي عام 1997. تُعدّ الجامعة الحلقة الأخيرة في سلسلة تعليمية متكاملة \"من رياض الأطفال إلى الجامعة\" تتبنّاها مؤسسة دوغوش. منذ تأسيسها، تحرص الجامعة على تقديم تعليم عالي الجودة بكادر أكاديمي متميز، والإسهام في عالم البحث العلمي. تضمّ الجامعة عشرين برنامج بكالوريوس في كليات الآداب والعلوم، والهندسة، والاقتصاد والعلوم الإدارية، والفنون والتصميم، إضافة إلى تسعة برامج درجة زمالة في مدرسة الدراسات المهنية المتقدمة، وثمانية برامج دراسات عليا في معهد العلوم الاجتماعية، وثلاثة برامج في معهد العلوم والتكنولوجيا. تقع الجامعة في الجانب الآسيوي من اسطنبول','2026-06-06 11:48:52','2026-06-12 09:45:44','[\"turkish\", \"english\"]','https://www.youtube.com/embed/9taXltNiOUI?si=QHILQte3-sohsAkU',0.0,NULL,NULL),(178,'جامعة ديمير اوغلو للعلوم','Demiroğlu Bilim Üniversitesi','اسطنبول','2006','private','https://demiroglubilim.edu.tr/','universities/NElAR6vnVjj21UjESWd2fzJiVou1VESY4xY0pPNc.png','\"[\\\"university-gallery\\\\/1781103085_6a2979ed81199.jpeg\\\",\\\"university-gallery\\\\/1781103085_6a2979ed854ac.jpeg\\\",\\\"university-gallery\\\\/1781103085_6a2979ed85b73.jpeg\\\",\\\"university-gallery\\\\/1781103085_6a2979ed86034.jpeg\\\"]\"',133,NULL,'تأسست جامعة ديمير أوغلو للعلوم (Demiroğlu Bilim Üniversitesi) في مدينة اسطنبول عام 2006 بمبادرة من مؤسسة أمراض القلب التركية (Türk Kardiyoloji Vakfı)، لتكون واحدة من أعرق الجامعات الخاصة المتخصصة في العلوم الصحية والطب في تركيا. تقع الجامعة في الجانب الأوروبي من اسطنبول، وتستفيد من شبكة مستشفيات فلورنس نايتنغيل (Florence Nightingale) التابعة لها لتقديم تدريب سريري عملي لطلاب الطب والتمريض والعلوم الصحية. تضمّ الجامعة كلية الطب وكلية العلوم والآداب وكلية العلوم الصحية، إضافة إلى مدرسة فلورنس نايتنغيل للتمريض ومدرسة الخدمات الصحية، إلى جانب معاهد للدراسات العليا في العلوم الصحية والاجتماعية. تُعدّ الجامعة من الوجهات المفضّلة للطلاب الدوليين والعرب الراغبين في دراسة الطب في تركيا، وذلك لجمعها بين العمق الأكاديمي والخبرة السريرية في مستشفيات جامعية مرموقة وموقع متميز في مدينة اسطنبول.','2026-06-06 11:50:35','2026-06-11 09:10:37','[\"turkish\", \"english\"]','https://www.youtube.com/embed/i5i5QBpPTb4?si=jXHfXvRCwJMY0ZpJ',0.0,NULL,NULL),(179,'جامعة يوكسيك اختصاص','Yüksek İhtisas Üniversitesi','انقرة','2017','private','https://yiu.edu.tr/','universities/47yJ5n9gR9ErRHBFZa7fpAQWlvf0Aq6VkyJ369MC.png','\"[\\\"university-gallery\\\\/1781174961_6a2a92b1abf31.jpeg\\\",\\\"university-gallery\\\\/1781174961_6a2a92b1b08d8.jpeg\\\",\\\"university-gallery\\\\/1781174961_6a2a92b1b10da.jpeg\\\",\\\"university-gallery\\\\/1781174961_6a2a92b1b17d3.jpeg\\\"]\"',156,NULL,'تأسست جامعة يوكسيك اختصاص (Yüksek İhtisas Üniversitesi) في العاصمة التركية أنقرة عام 2011 بمبادرة من مؤسسة مستشفى الاختصاص العالي التركي ومؤسسة المستشفيات الحكومية التركية، وانطلقت كلية الطب فيها بالتدريس عام 2015 مع 51 طالبًا. تُعدّ الجامعة من المؤسسات الخاصة غير الربحية المتخصصة في العلوم الصحية، وترفع شعار \"نحن جامعة الحكمة الجماعية\" تأكيدًا على نهجها التعاوني في التعليم والبحث. تضمّ الجامعة كلية الطب، وكلية العلوم الصحية، وكلية العلوم الرياضية، ومدرسة اللغات الأجنبية، ومدرسة مهنية للخدمات الصحية، ومدرسة مهنية عامة، ومعهدًا للدراسات العليا في العلوم الصحية، مما يوفّر بيئة أكاديمية متكاملة. تستفيد الجامعة من تعاون وثيق مع مستشفيات الاختصاص العالي في أنقرة لتدريب طلابها سريريًا في بيئة طبية متقدمة. تُعدّ جامعة يوكسيك اختصاص خيارًا متميزًا للطلاب الدوليين والعرب الراغبين في دراسة الطب والصحة في تركيا في عاصمة الدولة بأسعار تنافسية وجودة عالية.','2026-06-06 12:06:22','2026-06-11 07:49:21','[\"turkish\"]','https://www.youtube.com/embed/24DnUUHn0_M?si=SWPaMnxTWcwlJRIJ',0.0,NULL,NULL),(180,'جامعة تشاغ','Çağ Üniversitesi','مرسين','1997','private','https://cag.edu.tr/','universities/Qg52hLG69kQlmHUmpRSV0RpiUkrl7z2lrlVp225b.png','\"[\\\"university-gallery\\\\/1781099100_6a296a5c66215.jpeg\\\",\\\"university-gallery\\\\/1781099100_6a296a5c694a4.jpeg\\\",\\\"university-gallery\\\\/1781099100_6a296a5c699ec.jpeg\\\",\\\"university-gallery\\\\/1781099100_6a296a5c69f69.jpeg\\\",\\\"university-gallery\\\\/1781099100_6a296a5c6a50f.jpeg\\\",\\\"university-gallery\\\\/1781099100_6a296a5c6afab.jpeg\\\"]\"',156,NULL,'تأسست جامعة تشاغ (Çağ Üniversitesi) في 9 يوليو 1997 بمبادرة من مؤسسة بايبوغان للتعليم (Bayboğan Eğitim Vakfı) في محافظة مرسين جنوب تركيا، لتكون أوّل جامعة خاصة في منطقة تشوكوروفا الزراعية الخصبة وأحد المراكز الثقافية المهمة في إقليم البحر المتوسط. تقع الجامعة على الطريق الدولي D.400 قرب بلدة ينيجة، على بُعد 22 كم غرب مدينة أضنة، و18 كم شرق مدينة طرسوس، و45 كم شرق مدينة مرسين، مما يجعلها في موقع مركزي يخدم ثلاث مدن كبرى.','2026-06-06 12:08:08','2026-06-11 09:51:58','[\"turkish\", \"english\"]','https://www.youtube.com/embed/Q1KvajoMv0Y?si=McmUxovPC3IXr7ON',0.0,NULL,NULL),(181,'جامعة يدي تبة','Yeditepe Üniversitesi','اسطنبول','1996','private','https://yeditepe.edu.tr/','universities/CZJfOYhXUN2JBRimKr6aIPrsFCiFj4XnYLIbsv9l.png','\"[\\\"university-gallery\\\\/1781172607_6a2a897fc4caa.jpeg\\\",\\\"university-gallery\\\\/1781172607_6a2a897fc75cd.jpeg\\\",\\\"university-gallery\\\\/1781172607_6a2a897fc7c74.jpeg\\\",\\\"university-gallery\\\\/1781172607_6a2a897fc82ae.jpeg\\\",\\\"university-gallery\\\\/1781172607_6a2a897fc8a11.jpeg\\\"]\"',45,NULL,'تأسست جامعة يدي تبة (Yeditepe Üniversitesi) في مدينة اسطنبول عام 1996 بمبادرة من مؤسسة اسطنبول للتعليم والثقافة (İSTEK)، وتُعدّ من أعرق وأكبر الجامعات الخاصة في تركيا. حصلت الجامعة على اسمها \"يدي تبة\" أي \"التلال السبع\" نسبةً إلى تلال اسطنبول السبعة التاريخية. تقع الجامعة في حرم جامعي ضخم في منطقة كايشداغ في الجانب الآسيوي من اسطنبول، يضمّ مرافق تعليمية واجتماعية ورياضية متكاملة، ويُعدّ من أكبر الحرم الجامعية الخاصة في تركيا. تضمّ الجامعة 13 كلية و64 برنامج بكالوريوس، تشمل: الطب، وطب الأسنان، والصيدلة، والتربية، والآداب والعلوم، والقانون، والاقتصاد والعلوم الإدارية، والاتصال، والهندسة، والعمارة، والعلوم الصحية، والفنون الجميلة، والتعاون التجاري، إضافة إلى مدرسة العلوم التطبيقية. تمتلك الجامعة مستشفى جامعيًا متقدمًا يخدم تدريب طلاب الطب وطب الأسنان والعلوم الصحية. تُعدّ يدي تبة وجهة جذابة للطلاب الدوليين والعرب، وتستقطب آلاف الطلاب من مختلف الجنسيات الراغبين في الدراسة في تركيا في جامعة شاملة بتخصصات متنوعة.','2026-06-06 12:11:34','2026-06-11 10:03:04','[\"turkish\", \"english\"]','https://www.youtube.com/embed/ti6bnWAHOuU?si=c6znQPRYdkhNC-b4',0.0,NULL,NULL),(182,'جامعة اجيباديم محمد علي ايدنلار','Acıbadem Mehmet Ali Aydınlar Üniversitesi','اسطنبول','2007','private','https://acibadem.edu.tr/','universities/nZs0sSZJYIcFvXpOhch5RiDn1tpMBlArZgJIXoua.png','\"[\\\"university-gallery\\\\/1780921725_6a26b57d68852.jpeg\\\",\\\"university-gallery\\\\/1780921725_6a26b57d6d6b6.jpeg\\\",\\\"university-gallery\\\\/1780921725_6a26b57d6e104.jpeg\\\",\\\"university-gallery\\\\/1780921725_6a26b57d6e999.jpeg\\\",\\\"university-gallery\\\\/1780921725_6a26b57d6f2a7.jpeg\\\",\\\"university-gallery\\\\/1780921725_6a26b57d6fb79.jpeg\\\"]\"',25,NULL,'تأسست جامعة اجيباديم محمد علي أيدنلار (Acıbadem Mehmet Ali Aydınlar Üniversitesi - ACU) في مدينة اسطنبول عام 2007 على يد رجل الأعمال محمد علي أيدنلار، مؤسس مجموعة اجيباديم الصحية، إحدى أكبر مجموعات الرعاية الصحية في تركيا والمنطقة. انطلقت الجامعة بالنشاط الأكاديمي عام 2009. تُعدّ الجامعة من المؤسسات غير الربحية المتخصصة في علوم الصحة، وتستفيد من شبكة مستشفيات اجيباديم الواسعة التي تضمّ أكثر من 20 مستشفى ومراكز طبية في تركيا والخارج، مما يوفّر لطلابها بيئة سريرية متطورة بمعايير دولية. تستقطب الجامعة 4,374 طالبًا في كلية الطب، وكلية الصيدلة، وكلية العلوم الصحية، وكلية الآداب والعلوم، وكلية الهندسة، إضافة إلى مدرستين مهنيتين وأربع مدارس عليا للدراسات العليا في العلوم الصحية والاجتماعية والطبيعية والتطبيقية وعلم الأورام. يقع الحرم الرئيسي (كرم أيدنلار) في الجانب الآسيوي من اسطنبول، وترتبط الجامعة بمستشفيي اجيباديم ماسلاك وأتاكنت للأغراض التعليمية والبحثية. تُعدّ ACU من أبرز الوجهات للطلاب الدوليين والعرب الراغبين في دراسة الطب في تركيا في بيئة سريرية متقدمة بمعايير عالمية.','2026-06-06 12:17:16','2026-06-11 10:38:03','[\"turkish\", \"english\"]','https://www.youtube.com/embed/kLouhYz_EQk?si=df5EaRtEvxWNWhv0',0.0,NULL,NULL),(183,'جامعة قادير هاس','Kadir Has Üniversitesi','اسطنبول','1997','private','https://khas.edu.tr/','universities/P7Aool4XzTDilZp1XrZHAqPjUwqSvCuutO9WQ4ot.png','\"[\\\"university-gallery\\\\/1781162698_6a2a62cab9422.jpeg\\\",\\\"university-gallery\\\\/1781162698_6a2a62cac67d4.jpeg\\\",\\\"university-gallery\\\\/1781162698_6a2a62cac7c63.jpeg\\\",\\\"university-gallery\\\\/1781162698_6a2a62cac8a47.jpeg\\\",\\\"university-gallery\\\\/1781162698_6a2a62cac9d81.jpeg\\\"]\"',65,NULL,'تأسست جامعة قادر هاس (Kadir Has Üniversitesi - KHAS) في مدينة اسطنبول عام 1997 بمبادرة من مؤسسة قادر هاس، وافتُتح حرمها الجامعي الرئيسي في حي جبالي/فاتح المطل على القرن الذهبي رسميًا في 13 فبراير 2002 بعد أربع سنوات من أعمال الترميم. يقع الحرم في مبنى تاريخي شيّده عام 1884 المعماري العثماني الأرمني هوفسيب أزنافور بوصفه مصنع تبغ، وحازت الجامعة عام 2003 جائزة \"أوروبا نوسترا\" تقديرًا لإحياء هذا المعلم التاريخي وتحويله إلى حرم جامعي حديث.','2026-06-06 12:19:35','2026-06-11 04:24:58','[\"english\"]','https://www.youtube.com/embed/FIMpjSbzwf0?si=V_SKnGzaQcM1fZoM',0.0,NULL,NULL),(184,'جامعة كاراتاي','Kto Karatay Üniversitesi','قونيا','2009','private','https://karatay.edu.tr/','universities/ztyHRognc8Z3jxkGAkjEp2o6ujerXLr8eW7pY7FO.png','\"[\\\"university-gallery\\\\/1781164164_6a2a688496f02.jpeg\\\",\\\"university-gallery\\\\/1781164164_6a2a68849ec57.jpeg\\\",\\\"university-gallery\\\\/1781164164_6a2a6884a01b8.jpeg\\\",\\\"university-gallery\\\\/1781164164_6a2a6884a180e.jpeg\\\",\\\"university-gallery\\\\/1781164164_6a2a6884a322a.jpeg\\\"]\"',139,NULL,'تأسست جامعة كاراتاي (KTO Karatay Üniversitesi) في مدينة قونيا وسط تركيا عام 2009 بمبادرة من مؤسسة غرفة تجارة قونيا للتعليم والصحة، وتعود جذورها التاريخية إلى مدرسة كاراتاي السلجوقية الشهيرة التي أسّسها الأمير جلال الدين كاراتاي عام 1251 م، مما يجعلها امتدادًا لإرث علمي عريق. التحق أوّل أفواج الطلاب بالجامعة في العام الدراسي 2010–2011، وتخرّجت أولى دفعاتها في يونيو 2013. تقع الجامعة في مدينة قونيا التاريخية التي تشتهر بكونها عاصمة الدولة السلجوقية ومدفن مولانا جلال الدين الرومي، مما يضفي على البيئة الدراسية بُعدًا ثقافيًا وروحيًا مميزًا. تضمّ الجامعة ست كليات هي: الحقوق، والهندسة والعلوم الطبيعية، والعلوم الاقتصادية والإدارية، والعلوم الاجتماعية والإنسانية، والفنون الجميلة والتصميم، وكلية الطب، إلى جانب ثلاث مدارس مهنية في القضاء والعلوم الصحية والتجارة والصناعة، وثلاث مدارس عليا في العلوم الصحية والعلوم التطبيقية واللغات الأجنبية. تُعدّ جامعة كاراتاي خيارًا متميزًا للطلاب الدوليين والعرب الراغبين في الدراسة في تركيا في بيئة آمنة وعريقة بأسعار تنافسية.','2026-06-06 12:20:03','2026-06-11 10:47:14','[\"turkish\", \"english\"]','https://www.youtube.com/embed/cVb4KMZ_IdE?si=a4gLJtXB2hx4_K2b',0.0,NULL,NULL),(185,'جامعة انطاليا للعلوم','Antalya Bilim Üniversitesi','انطاليا','2012','private','https://antalya.edu.tr/','universities/7bTliDSagfiLFoFUYyDSgBzA5suPfq3sD4g5hJ6s.png','\"[\\\"university-gallery\\\\/1781087432_6a293cc8dd0f7.jpeg\\\",\\\"university-gallery\\\\/1781087432_6a293cc8e3492.jpeg\\\",\\\"university-gallery\\\\/1781087432_6a293cc8e40a9.jpeg\\\",\\\"university-gallery\\\\/1781087432_6a293cc8e4921.jpeg\\\"]\"',121,NULL,'تأسست جامعة أنطاليا للعلوم (Antalya Bilim Üniversitesi) في مدينة أنطاليا الساحلية جنوب تركيا عام 2010، لتكون أوّل جامعة خاصة في أنطاليا تهدف إلى دعم التطور العلمي على المستويين المحلي والعالمي. يقع الحرم الجامعي على مساحة 300,000 متر مربع، صُمّم بأسلوب يدمج بين الطابع المعماري السلجوقي الأصيل والتصميم الحديث، مما يمنحه هوية بصرية فريدة بين الجامعات التركية. تضمّ الجامعة 7 كليات و4 مدارس متخصصة، تشمل: كلية طب الأسنان، وكلية الفنون الجميلة والعمارة، وكلية الحقوق، وكلية الاقتصاد والعلوم الإدارية والاجتماعية، وكلية الهندسة والعلوم الطبيعية، وكلية العلوم الصحية، وكلية السياحة، إلى جانب مدرسة مهنية، ومدرسة مهنية للخدمات الصحية، ومدرسة الطيران المدني، ومدرسة اللغات الأجنبية. تتميّز كلية السياحة في الجامعة بفرص تدريبية كبيرة في فنادق ومنتجعات أنطاليا العالمية. تُعدّ جامعة أنطاليا للعلوم وجهة جذابة للطلاب الدوليين والعرب، وتستفيد من موقعها في إحدى أجمل المدن السياحية في تركيا والعالم بمناخها المعتدل وتكاليفها المعيشية المعقولة.','2026-06-06 12:31:20','2026-06-12 06:44:13','[\"turkish\", \"english\"]','https://www.youtube.com/embed/G-lOVOlS4fY?si=DR8GCekhdmgpQNhX',0.0,NULL,NULL),(186,'جامعة استينيا','İstinye Üniversitesi','اسطنبول','2015','private','https://www.istinye.edu.tr/','universities/TvDC0VXNQAMv5T8SuDN8dJ2GCIXtVZdgWWldHdB0.png','\"[\\\"university-gallery\\\\/1781078501_6a2919e52be46.webp\\\",\\\"university-gallery\\\\/1781078501_6a2919e52f86e.webp\\\",\\\"university-gallery\\\\/1781078501_6a2919e52ff73.webp\\\",\\\"university-gallery\\\\/1781078501_6a2919e530437.webp\\\",\\\"university-gallery\\\\/1781078501_6a2919e530a78.webp\\\",\\\"university-gallery\\\\/1781078501_6a2919e5310e2.webp\\\"]\"',57,NULL,'جامعة استينيا هي جامعة حديثة في تركيا تأسست في عام 2015 بواسطة مؤسسة الأناضول، وتقع في مدينة اسطنبول غربي تركيا. تتميز جامعة استينيا بتقديم برامج تعليمية متنوعة في مجالات العلوم الإنسانية والعلوم الاجتماعية والهندسة والعلوم الطبيعية والصحية والتكنولوجيا.\r\n\r\nتعتمد جامعة استينيا على البحث العلمي والتطوير التكنولوجي لتطوير أنظمتها التعليمية والتعلم الإلكتروني، كما تهتم الجامعة بتوفير بيئة تعليمية حديثة ومريحة للطلاب. وتقدم الجامعة فرصًا للطلاب للمشاركة في الأنشطة الثقافية والرياضية والاجتماعية من خلال العديد من النوادي والفرق الطلابية المختلفة.','2026-06-06 13:38:16','2026-06-12 04:33:58','[\"turkish\", \"english\"]','https://www.youtube.com/embed/PPnS6ZzPNos?si=AxrJBEYn9qm4m2j5',0.0,NULL,NULL),(187,'جامعة ابن خلدون','İbn Haldun Üniversitesi','اسطنبول','2015','private','https://ihu.edu.tr/','universities/BV14fJv1k197Xy7jar5ecWIalREj4YFBsCXc2Ix3.png','\"[\\\"university-gallery\\\\/1780920635_6a26b13baeb67.jpeg\\\",\\\"university-gallery\\\\/1780920635_6a26b13bb5268.jpeg\\\",\\\"university-gallery\\\\/1780920635_6a26b13bb5e9a.jpeg\\\",\\\"university-gallery\\\\/1780920635_6a26b13bb6776.jpeg\\\",\\\"university-gallery\\\\/1780920635_6a26b13bb7018.jpeg\\\",\\\"university-gallery\\\\/1780920635_6a26b13bb7a51.jpeg\\\"]\"',123,NULL,'تأسست جامعة ابن خلدون (Ibn Haldun Üniversitesi - IHU) في مدينة اسطنبول عام 2015 بمبادرة من مؤسسة الشباب التركي وخدمات التعليم (TÜRGEV)، وانطلقت بالنشاط الأكاديمي في العام الدراسي 2017–2018. تقع الجامعة في حي باشاك شهير في الجانب الأوروبي من اسطنبول، في مجمع جامعي تم تصميمه على غرار العمارة العثمانية للمدارس التقليدية، وافتُتح رسميًا في أكتوبر 2020. سُمّيت الجامعة تيمنًا بالعالم العربي والمؤرخ ابن خلدون مؤسس علم الاجتماع، وتُركّز برامجها على العلوم الاجتماعية والإنسانية. تتبنّى الجامعة نهجًا متعدد اللغات في التدريس، يشمل التركية والإنكليزية والعربية، مما يجعلها وجهة فريدة للطلاب العرب.','2026-06-06 13:44:35','2026-06-12 04:51:37','[\"turkish\", \"english\", \"arabic\"]','https://www.youtube.com/embed/SifpW6ueEjM?si=bPz9YhcH0zpRs7of',0.0,NULL,NULL),(188,'جامعة طوروس','Toros Üniversitesi','مرسين','2009','private','https://toros.edu.tr/','universities/FgopRqHqBcY2kO2TIa4oyqb0jZuU0svlembgJppe.png','\"[\\\"university-gallery\\\\/1781104813_6a2980ad8db1e.jpeg\\\",\\\"university-gallery\\\\/1781104813_6a2980ad91ac0.jpeg\\\",\\\"university-gallery\\\\/1781104813_6a2980ad92167.jpeg\\\",\\\"university-gallery\\\\/1781104813_6a2980ad926dd.jpeg\\\"]\"',177,NULL,'تأسست جامعة طوروس (Toros Üniversitesi) في مدينة مرسين جنوب تركيا في 23 يوليو 2009 بمبادرة من مؤسسة مرسين للتعليم (Mersin Eğitim Vakfı) التي أنشأها عام 1979 مجموعة من المعلمين المثاليين بهدف تقديم خدمات تعليمية متميّزة في المنطقة. تخرّجت أولى دفعاتها في العام الدراسي 2014–2015. سُمّيت الجامعة نسبةً إلى جبال طوروس التي تفصل ساحل البحر المتوسط عن هضبة الأناضول الوسطى، وتقع في مدينة مرسين الساحلية التي تضمّ أكبر ميناء بحري في تركيا، مما يمنح الطلاب فرصة الدراسة في بيئة طبيعية معتدلة وبتكلفة معيشية أقل من المدن الكبرى.','2026-06-06 13:46:16','2026-06-12 04:58:45','[\"turkish\", \"english\"]','https://www.youtube.com/embed/QCtg0HCmkRA?si=cY_ImLeYAAq0dqkV',0.0,NULL,NULL),(189,'جامعة اسطنبول للتجارة','İstanbul Ticaret Üniversitesi','اسطنبول','2001','private','https://ticaret.edu.tr/','universities/VX6z7ZmoOvEPMTh7CSzKE0YzdoD7NLYrebkTAmDD.png','\"[\\\"university-gallery\\\\/1781081028_6a2923c4e81f4.jpeg\\\",\\\"university-gallery\\\\/1781081028_6a2923c4eeece.jpeg\\\",\\\"university-gallery\\\\/1781081028_6a2923c4ef6bf.jpeg\\\",\\\"university-gallery\\\\/1781081028_6a2923c4f0181.jpeg\\\",\\\"university-gallery\\\\/1781081028_6a2923c4f0963.jpeg\\\",\\\"university-gallery\\\\/1781081028_6a2923c4f0fc7.jpeg\\\"]\"',124,NULL,'تأسست جامعة اسطنبول للتجارة (İstanbul Ticaret Üniversitesi) في مدينة اسطنبول عام 2001 لتكون من أوائل الجامعات الخاصة في تركيا. تعود جذور الجامعة إلى عام 1882 حين تأسّست غرفة تجارة درسعادة (Dersaadet) في الدولة العثمانية، ثم اقتُرح في عام 1992 إنشاء جامعة تابعة لغرفة تجارة اسطنبول، وتمّ الاعتماد رسميًا تحت اسم \"جامعة التجارة\"، بدأت التدريس في 2001 بـ73 طالبًا. تمتلك الجامعة حرمَين رئيسيَّين: حرم سوتلوجة (Sütlüce) المطل على القرن الذهبي ويضمّ كليات إدارة الأعمال والاتصال والإنسانيات والقانون، وحرم كوتشوك يالي (Küçükyalı) في الجانب الآسيوي ويضمّ كليتَي الهندسة والعمارة والتصميم.','2026-06-06 13:47:54','2026-06-12 05:07:32','[\"turkish\", \"english\"]','https://www.youtube.com/embed/6btIwiWaXtU?si=q6SuGDrMTlzR_Ikd',0.0,NULL,NULL),(190,'جامعة نوح ناجي يازجين','Nuh Naci Yazgan Üniversitesi','قيصري','2009','private','https://nny.edu.tr/','universities/3RWEN5g9JnXJaOJLFtxzKs9OoXeg7nWOsEd1mbBE.png','\"[\\\"university-gallery\\\\/1781170928_6a2a82f0ebcbc.jpeg\\\",\\\"university-gallery\\\\/1781170928_6a2a82f0f1c29.jpeg\\\",\\\"university-gallery\\\\/1781170928_6a2a82f0f24d3.jpeg\\\",\\\"university-gallery\\\\/1781170928_6a2a82f0f29e3.jpeg\\\"]\"',176,NULL,'تأسست جامعة نوح ناجي يازجين (Nuh Naci Yazgan Üniversitesi) في مدينة قيصري وسط تركيا عام 2009 بمبادرة من مؤسسة قيصري للتعليم العالي والمساعدات. سُمّيت الجامعة تيمنًا برجل الأعمال نوح ناجي يازجين الذي يُعدّ من أبرز الشخصيات في تطوير الصناعة التركية. تقع الجامعة في إحدى أهم مدن الأناضول الصناعية والتجارية، مما يتيح للطلاب فرصًا واسعة للتدريب والتوظيف بعد التخرج.','2026-06-06 13:52:52','2026-06-12 05:15:30','[\"turkish\", \"english\"]','https://www.youtube.com/embed/OjnO8tLo6Kw?si=2217J10WScq1q_8p',0.0,NULL,NULL),(191,'جامعة اسطنبول اسنيورت','İstanbul Esenyurt Üniversitesi','اسطنبول','2013','private','https://www.esenyurt.edu.tr/','universities/9bIsPca4DKCW84tiwOHSiAjIlIghvVvz4SsJesLf.png','\"[\\\"university-gallery\\\\/1780929713_6a26d4b1b43cc.webp\\\",\\\"university-gallery\\\\/1780929713_6a26d4b1bcdaf.webp\\\",\\\"university-gallery\\\\/1780929713_6a26d4b1bdf4a.webp\\\",\\\"university-gallery\\\\/1780929713_6a26d4b1bf0d3.webp\\\",\\\"university-gallery\\\\/1780929713_6a26d4b1c01a7.webp\\\"]\"',183,NULL,'تأسست جامعة اسطنبول إسنيورت (İstanbul Esenyurt Üniversitesi) في مدينة اسطنبول عام 2013 بدعم من المؤسسة غير الربحية \"يلدزلار\" (Yıldızlar) المتخصصة في الثقافة والصحة والتعليم. تقع الجامعة في حي إسنيورت في الجانب الأوروبي من اسطنبول، أحد أكبر أحياء المدينة وأكثرها حيوية.','2026-06-06 14:09:34','2026-06-12 05:23:20','[\"turkish\", \"english\"]','https://www.youtube.com/embed/gsQ90sRJ71E?si=705VO9eW_otEp0ji',0.0,NULL,NULL),(192,'جامعة إسطنبول نيشانتاشي','İstanbul Nişantaşı Üniversitesi','اسطنبول','2012','private','https://www.nisantasi.edu.tr/','universities/dOgB5PMJQ3FMtGDIbz7M3CBOIhWLOoHLnFkAi4Dp.png','\"[\\\"university-gallery\\\\/1780918185_6a26a7a92291e.jpeg\\\",\\\"university-gallery\\\\/1780918185_6a26a7a92b33b.jpeg\\\",\\\"university-gallery\\\\/1780918185_6a26a7a92c194.jpeg\\\",\\\"university-gallery\\\\/1780918185_6a26a7a92d002.webp\\\",\\\"university-gallery\\\\/1780918185_6a26a7a92de09.jpeg\\\",\\\"university-gallery\\\\/1780918185_6a26a7a92ec0f.webp\\\"]\"',155,NULL,'تعد جامعة نيشان تاشي إحدى الجامعات المتميزة في تركيا، حيث تركز على توفير بيئة تعليمية تدعم التطور الشخصي والأكاديمي للطلاب. تقدم الجامعة مجموعة متنوعة من البرامج الأكاديمية عبر كلياتها المختلفة، مما يمنح الطلاب الفرصة للتخصص في مجالات متعددة تواكب احتياجات السوق الحديثة.\r\n\r\nتضم جامعة نيشان تاشي كلية الطب التي توفر تعليمًا شاملاً ومكثفًا يتناول أحدث التطورات في الرعاية الصحية، وتعمل على تخريج أطباء مؤهلين بأعلى المعايير الطبية والعلمية. بالإضافة إلى ذلك، تقدم كلية طب الأسنان برامج دراسية تشمل التدريب النظري والعملي لتأهيل الطلاب ليكونوا من رواد هذا المجال في المستقبل.\r\n\r\nتسعى كلية الهندسة والعلوم التطبيقية إلى تأهيل مهندسين مبدعين قادرين على مواجهة التحديات التكنولوجية المعاصرة، فيما تقدم كلية العلوم الإنسانية والاجتماعية برامج تهدف إلى إعداد متخصصين يمتلكون القدرة على فهم وتحليل القضايا الاجتماعية بشكل فعال. كما توفر كلية العلوم الصحية دورات حديثة في إدارة الرعاية الصحية وخدماتها، مما يدعم تطوير القطاع الصحي.\r\n\r\nيتميز الحرم الجامعي لجامعة نيشان تاشي بمرافقه المتطورة التي تتيح للطلاب الاستفادة من بيئة تعليمية متكاملة، ويعكس التزام الجامعة برؤية شاملة لدعم الابتكار والتطوير المهني والأكاديمي.','2026-06-06 14:11:51','2026-06-11 11:07:19','[\"turkish\", \"english\"]','https://www.youtube.com/embed/fhqD2STaAas?si=0n7UGp0oHerYWJLc',0.0,NULL,NULL),(193,'جامعة اوفوك','Ufuk Üniversitesi','انقرة','1999','private','https://ufuk.edu.tr/','universities/TmsG8iEZHmgoybCFzue1XuXIO1veoSNkXlGbANNv.png','\"[\\\"university-gallery\\\\/1781090645_6a29495522649.jpeg\\\",\\\"university-gallery\\\\/1781090645_6a2949552db69.jpeg\\\",\\\"university-gallery\\\\/1781090645_6a2949552e79a.jpeg\\\",\\\"university-gallery\\\\/1781090645_6a2949553091d.jpeg\\\",\\\"university-gallery\\\\/1781090645_6a29495531cf7.jpeg\\\",\\\"university-gallery\\\\/1781090645_6a2949553400f.jpeg\\\"]\"',151,NULL,'تأسست جامعة اوفوك (Ufuk Üniversitesi) في العاصمة التركية أنقرة عام 1999 بموجب القانون رقم 4488 الصادر في الجريدة الرسمية بتاريخ 18 ديسمبر 1999، وبدأت نشاطها التعليمي في العام الدراسي 2002–2003. أسستها مؤسسة تركيا لمساعدة ضحايا حوادث المرور (Türkiye Trafik Kazaları Yardım Vakfı) التي يعود تاريخها إلى عام 1972، لتكون من الجامعات الخاصة التي تجمع بين الأبحاث العلمية والتعليم التطبيقي في مجالات الصحة والقانون والإدارة والهندسة. تضم الجامعة حرمَين جامعيَّين رئيسيَّين في أنقرة هما حرم إنجك (İncek) وحرم بالغات (Balgat)، إضافة إلى مستشفى الدكتور رضوان إيجة للأبحاث والتطبيقات الصحية الذي يعمل بطاقة 220 سريرًا.','2026-06-06 14:12:18','2026-06-10 08:24:05','[\"turkish\"]','https://www.youtube.com/embed/kqO9QzHefrw?si=ybrepGkXYnF8Rm1P',0.0,NULL,NULL),(194,'جامعة ياشار','Yaşar Üniversitesi','ازمير','2001','private','https://yasar.edu.tr/','universities/85v1vKql3KRX0aQc8sVPeVPPJpU9DbHdrsiiKY5g.png','\"[\\\"university-gallery\\\\/1781172150_6a2a87b665888.jpeg\\\",\\\"university-gallery\\\\/1781172150_6a2a87b66835c.jpeg\\\",\\\"university-gallery\\\\/1781172150_6a2a87b668879.jpeg\\\",\\\"university-gallery\\\\/1781172150_6a2a87b668d89.jpeg\\\"]\"',99,NULL,'تأسست جامعة ياشار (Yaşar Üniversitesi) في مدينة إزمير غرب تركيا عام 2001 بقرار من البرلمان التركي بتاريخ 29 مارس 2001، بمبادرة من مؤسسة سلجوق ياشار للرياضة والتعليم، وانطلقت بالنشاط الأكاديمي في العام الدراسي 2002–2003 في مقرها الأول في حي ألسنجاق. افتُتح حرم سلجوق ياشار في بورنوفا عام 2008 ليكون الحرم الرئيسي للجامعة.','2026-06-06 14:28:17','2026-06-11 07:02:30','[\"english\"]','https://www.youtube.com/embed/EPhUQwOGluc?si=huqOEa_GELayOX0w',0.0,NULL,NULL),(195,'جامعة اتيليم','Atılım Üniversitesi','انقرة','1997','private','https://www.atilim.edu.tr/tr','universities/zw9GEYXJwSOfrDsjdZAk76roWIVWJ2qfVvjupojQ.png','\"[\\\"university-gallery\\\\/1780921390_6a26b42ea30d5.webp\\\",\\\"university-gallery\\\\/1780921390_6a26b42ea8744.webp\\\",\\\"university-gallery\\\\/1780921390_6a26b42ea94e3.webp\\\",\\\"university-gallery\\\\/1780921390_6a26b42eaa046.webp\\\",\\\"university-gallery\\\\/1780921390_6a26b42eaa815.webp\\\",\\\"university-gallery\\\\/1780921390_6a26b42eaaf33.webp\\\"]\"',69,NULL,'تأسست جامعة اتيليم كجامعة أهلية تهدف إلى توفير تعليم عالي الجودة وإجراء البحوث والمساهمة في مستقبل البلد في العاصمة التركية أنقرة. تأسست بواسطة مؤسسة اتيليم في 15 يوليو 1997 وهي جامعة خاصة تخضع لأحكام القانون رقم 2547 المتعلق بمؤسسات التعليم العالي التابعة للمؤسسات الخاصة. تحقق الجامعة نجاحات ملحوظة في التصنيفات المحلية والدولية وذلك بالاعتماد على معايير مثل الأبحاث والتعليم والرؤية الدولية والدخل الصناعي وغيرها. وفي إحدى تصنيفات شركة Times Higher Education (THE) العالمية، جاءت الجامعة في المركز الرابع بين الجامعات الأهلية في تركيا، وفي تصنيف فيزيائيات العلوم الفيزيائية جاءت الجامعة في المركز الثاني في تركيا، وفي التصنيف الخاص بـ BRICS والاقتصادات الناشئة، جاءت الجامعة في المركز السادس بين جميع الجامعات في تركيا والرابع بين الجامعات الأهلية. ووفقاً لتصنيف SCIMAGO الإسبانية، التي تركز على الجودة والابتكار والحساسية تجاه المجتمع، جاءت الجامعة في المركز الحادي والعشرين في تركيا والسادس بين الجامعات الأهلية. وفي تصنيف URAP التركي الذي يعتمد على البحث، جاءت الجامعة في المركز الـ 42 بين جميع الجامعات في تركيا والسابع بين الجامعات الأهلية، وفي تصنيف QS، الذي يركز على البحث والتعليم والعالمية، دخلت الجامعة ضمن أول 250 جامعة في “الدول الصاعدة في أوروبا وآسيا الوسطى','2026-06-06 14:30:29','2026-06-12 05:41:55','[\"turkish\", \"english\"]','https://www.youtube.com/embed/_xBP2SFL9AQ?si=_295bkU_XyHet8S4',0.0,NULL,NULL),(196,'جامعة ميف','Mef Üniversitesi','اسطنبول','2012','private','https://mef.edu.tr/','universities/XSf7wdljcq2tXODisFVyphXXwZHCbIg0pzJKCHTj.png','\"[\\\"university-gallery\\\\/1781170530_6a2a8162e69c2.jpeg\\\",\\\"university-gallery\\\\/1781170530_6a2a8162e8e12.jpeg\\\",\\\"university-gallery\\\\/1781170530_6a2a8162e9438.jpeg\\\",\\\"university-gallery\\\\/1781170530_6a2a8162e99ae.jpeg\\\",\\\"university-gallery\\\\/1781170530_6a2a8162e9f68.jpeg\\\"]\"',152,NULL,'تأسست جامعة ميف (MEF Üniversitesi) في مدينة اسطنبول عام 2012 بمبادرة من مؤسسات ميف التعليمية، وهي مجموعة تعليمية عريقة تمتلك أكثر من 30 عامًا من الخبرة في تقديم التعليم عالي الجودة في تركيا. انطلقت الجامعة بالنشاط الأكاديمي في العام الدراسي 2014–2015. تشتهر جامعة ميف عالميًا بكونها أوّل جامعة في العالم تعتمد نموذج \"الفصل المقلوب\" (Flipped Classroom) على مستوى الجامعة بأكملها، حيث يُنقل المحتوى المعرفي إلى الطلاب قبل المحاضرة عبر فيديوهات تعليمية على منصة رقمية، فيتحوّل وقت الفصل إلى نقاش تفاعلي وحلّ مشكلات وتعلّم تشاركي.','2026-06-06 14:32:55','2026-06-11 06:35:30','[\"english\"]','https://www.youtube.com/embed/kHrMzGzfY5k?si=tx_v_oykJFZu5tiO',0.0,NULL,NULL),(197,'جامعة افراسيا','Avrasya Üniversitesi','طرابزون','2010','private','https://avrasya.edu.tr/','universities/sQmH8DYkXz0g3HjH897OLLyh40fkqBK6qM7IuC8l.png','\"[\\\"university-gallery\\\\/1781083125_6a292bf5ae5c1.jpeg\\\",\\\"university-gallery\\\\/1781083125_6a292bf5ba514.jpeg\\\",\\\"university-gallery\\\\/1781083125_6a292bf5bb6f9.jpeg\\\",\\\"university-gallery\\\\/1781083125_6a292bf5bc76e.jpeg\\\",\\\"university-gallery\\\\/1781083125_6a292bf5bd785.jpeg\\\",\\\"university-gallery\\\\/1781083125_6a292bf5be87d.jpeg\\\"]\"',179,NULL,'تأسست جامعة افراسيا (Avrasya Üniversitesi) في مدينة طرابزون شمال شرق تركيا عام 2010، لتكون أوّل جامعة خاصة (مؤسسة) في منطقة البحر الأسود، وثاني مؤسسة للتعليم العالي في طرابزون بعد جامعة كاراديني التقنية الحكومية. تقع الجامعة في موقع استراتيجي يجمع بين أوروبا وآسيا (ومن هنا اسمها \"أوراسيا\")، وتستقطب طلابًا من تركيا والقوقاز والشرق الأوسط وآسيا الوسطى.','2026-06-06 14:38:48','2026-06-10 06:18:45','[\"turkish\"]','https://www.youtube.com/embed/co4lAeNFxsE?si=Bh4ktVVL5tMSMakb',0.0,NULL,NULL),(198,'جامعة بيروني','Biruni Üniversitesi','اسطنبول','2014','private','https://www.biruni.edu.tr/','universities/97aJFvNf5x7kTse1eFwa673Dxizh6KuRQb9eNOwL.png','\"[\\\"university-gallery\\\\/1780930268_6a26d6dc16fe1.webp\\\",\\\"university-gallery\\\\/1780930268_6a26d6dc19517.webp\\\",\\\"university-gallery\\\\/1780930268_6a26d6dc19d01.webp\\\",\\\"university-gallery\\\\/1780930268_6a26d6dc1a4a6.webp\\\",\\\"university-gallery\\\\/1780930268_6a26d6dc1ac80.webp\\\"]\"',82,NULL,'تأسست جامعة بيروني (Biruni Üniversitesi) في مدينة اسطنبول في 27 فبراير 2014 بقرار من البرلمان التركي بموجب القانون رقم 6525، بمبادرة من مؤسسة دنيا للتعليم. سُمّيت الجامعة تيمنًا بالعالم العربي والمسلم أبو الريحان البيروني الذي وصفته منظمة اليونسكو عام 1974 بـ\"العبقري الكوني\" تقديرًا لإسهاماته في الرياضيات والفلك والصيدلة والجغرافيا والتاريخ. تُعدّ الجامعة من الجامعات المتخصصة في القطاع الصحي، وأكثر جامعات الصحة شمولًا في تركيا، حيث تقدّم 26 برنامجًا في 6 كليات ومعاهد ومدارس مهنية. تشمل الكليات: الطب، وطب الأسنان، والصيدلة، والعلوم الصحية، والتربية، والهندسة والعلوم الطبيعية. تقع الجامعة في قلب مدينة اسطنبول قرب أسوار توبكابي التاريخية، على مسافة قصيرة سيرًا من محطة كازليجشمة في خط مرمراي ومحطة جويزلباغ للمتروبوس، وقرب نفق أوراسيا. يمنح هذا الموقع الجامعة ميزة فريدة بدمج الحياة الجامعية بالنسيج التاريخي لاسطنبول. تستقطب جامعة بيروني طلابًا عربًا ودوليين، وتُعدّ من الجامعات الخاصة المفضّلة للراغبين في دراسة الطب وطب الأسنان والصيدلة في تركيا.','2026-06-06 14:46:52','2026-06-12 07:08:06','[\"turkish\", \"english\"]','https://www.youtube.com/embed/ykl-apaZDDY?si=G2MD_Yu_FkJg4Zxn',0.0,NULL,NULL),(199,'جامعة أوستيم التقنية','OSTİM Teknik Üniversitesi','انقرة','2017','private','https://www.ostimteknik.edu.tr/','universities/ckYgLUpCAMXtkPCYQkwFt8qVj48IqNdODXPQBMe2.png','\"[\\\"university-gallery\\\\/1780916202_6a269feae8989.jpeg\\\",\\\"university-gallery\\\\/1780916202_6a269feaf1064.jpeg\\\",\\\"university-gallery\\\\/1780916202_6a269feaf2055.jpeg\\\",\\\"university-gallery\\\\/1780916202_6a269feaf3173.jpeg\\\"]\"',NULL,NULL,'تأسست جامعة أوستيم التقنية (OSTİM Teknik Üniversitesi - OTU) في العاصمة التركية أنقرة عام 2017 بمبادرة من مؤسسة OSTİM (مركز الشرق الأوسط للصناعة والتجارة)، لتكون أوّل جامعة تقنية متخصصة في تركيا تنشأ في قلب منطقة صناعية. تقع الجامعة داخل منطقة OSTİM الصناعية المنظّمة في أنقرة، التي تضمّ أكثر من 6,500 شركة تعمل في تصنيع الآلات والمعالجة المعدنية والإلكترونيات وآلات البناء والسيارات والبلاستيك والمطاط والأدوات الطبية. هذا الموقع الفريد يمنح طلاب الجامعة وصولًا مباشرًا إلى التدريب الميداني وفرص التوظيف في مئات الشركات','2026-06-06 15:00:04','2026-06-12 06:31:06','[\"turkish\", \"english\"]','https://www.youtube.com/embed/o-Mwk3exBGM?si=Mg9cBdTnM93_X94H',0.0,NULL,NULL),(200,'جامعة اسطنبول اريل','İstanbul Arel Üniversitesi','اسطنبول','2007','private','https://www.istanbularel.edu.tr/','universities/Q3pUMLVxWunQMYCfPX2Z4uvp8cSIaRlZsHRzyO0Q.png','\"[\\\"university-gallery\\\\/1780930382_6a26d74e3ca64.webp\\\",\\\"university-gallery\\\\/1780930382_6a26d74e43b7f.webp\\\",\\\"university-gallery\\\\/1780930382_6a26d74e44e77.webp\\\",\\\"university-gallery\\\\/1780930382_6a26d74e45ebc.webp\\\",\\\"university-gallery\\\\/1780930382_6a26d74e46fcb.webp\\\",\\\"university-gallery\\\\/1780930382_6a26d74e48155.webp\\\"]\"',127,NULL,'تأسست جامعة اسطنبول أريل (İstanbul Arel Üniversitesi) في مدينة اسطنبول عام 2007 بمبادرة من مؤسسة كمال غوزوكارا للتعليم والثقافة، بموجب القانون رقم 2809/5656 الإضافي 76 المنشور في الجريدة الرسمية بتاريخ 18 مايو 2007. تنتمي الجامعة إلى مؤسسات أريل التعليمية التي بدأت نشاطها التعليمي في العام الدراسي 1990–1991 بإنشاء مدرسة أريل، ثم توسّعت لتشمل روضة أطفال ومدرسة ابتدائية وإعدادية وثانوية أناضولية وثانوية علوم ومجمع رياضي وثقافي. تقع الجامعة في الجانب الأوروبي من اسطنبول، في حرم رئيسي حديث في منطقة سفاكوي. تضمّ الجامعة 8 كليات تتضمن أكثر من 40 برنامج بكالوريوس و28 برنامج ماجستير و7 برامج دكتوراه و39 برنامج درجة زمالة. تشمل الكليات: العلوم والآداب، والاقتصاد والعلوم الإدارية، والهندسة، والعمارة، والفنون الجميلة والاتصال، والقانون، والعلوم الصحية، والتربية. تستقطب الجامعة طلابًا دوليين وعربًا، وتُعدّ خيارًا جذابًا للراغبين في الدراسة في تركيا في جامعة شاملة بتخصصات متنوعة وأسعار دراسية تنافسية في اسطنبول.','2026-06-06 15:14:27','2026-06-12 06:22:07','[\"turkish\", \"english\"]','https://www.youtube.com/embed/lQ3n6GxwQTw?si=gd5VHxXgkYgWi2WR',0.0,NULL,NULL),(201,'جامعة تيد','Ted Üniversitesi','انقرة','2009','private','https://tedu.edu.tr/','universities/IHRX6fQhuTRinmEc3CmPCmFkwv9wGrtd3QSCpYrJ.png','\"[\\\"university-gallery\\\\/1781101596_6a29741ce51f9.jpeg\\\",\\\"university-gallery\\\\/1781101596_6a29741ceb3f7.jpeg\\\",\\\"university-gallery\\\\/1781101596_6a29741cebe21.jpeg\\\",\\\"university-gallery\\\\/1781101596_6a29741cec684.jpeg\\\"]\"',120,NULL,'تأسست جامعة تيد (TED University) في العاصمة التركية أنقرة في 7 يوليو 2009 بمبادرة من مؤسسة جمعية التعليم التركية للتعليم العالي (TED)، وانطلقت بالنشاط الأكاديمي في العام الدراسي 2012–2013 بأوّل دفعة ضمّت 320 طالبًا. ترتكز الجامعة على إرث أكاديمي عمره 93 عامًا تمتلكه جمعية التعليم التركية، وهي من أعرق المؤسسات التعليمية في تركيا. تقع الجامعة في حرم جامعي حضري وسط أنقرة، مما يمنح الطلاب وصولًا مباشرًا إلى الحياة الثقافية والاقتصادية في عاصمة الدولة. تضمّ الجامعة خمس كليات هي: العمارة، والآداب والعلوم، والعلوم الاقتصادية والإدارية، والتربية، والهندسة. تعتمد الجامعة اللغة الإنكليزية لغةً رئيسيةً للتدريس في جميع برامجها، مع فصل تحضيري للغة. تُعدّ تيد من الجامعات الخاصة المتميزة في تركيا التي تركّز على التعليم بأساليب مبتكرة والبحث الأكاديمي الجاد، وتستقطب طلابًا دوليين من مختلف الجنسيات يبحثون عن جودة التعليم في بيئة أكاديمية متطورة في قلب العاصمة.','2026-06-06 15:56:27','2026-06-10 11:26:36','[\"english\"]','https://www.youtube.com/embed/FDrphJbSLuI?si=NYetgnHjWvkX1slk',0.0,NULL,NULL),(202,'جامعة اسطنبول كولتور','İstanbul Kültür Üniversitesi','اسطنبول','1997','private','https://www.iku.edu.tr/','universities/HrcnjbFSUK3JtbMlxqSOF8YsD3HHU18iJW4Agtam.png','\"[\\\"university-gallery\\\\/1780930829_6a26d90d5af67.webp\\\",\\\"university-gallery\\\\/1780930829_6a26d90d6532c.webp\\\"]\"',147,NULL,'تأسست جامعة اسطنبول كولتور (İstanbul Kültür Üniversitesi - IKU) في مدينة اسطنبول عام 1997 بمبادرة من مؤسسة كلية كولتور للتعليم (KEV) بموجب القانون رقم 4281 الصادر عن البرلمان التركي بتاريخ 9 يوليو 1997. تعود جذور المؤسسة إلى عام 1960 حين تأسّست كلية كولتور، ثم تطوّرت إلى جامعة بعد سبعة وثلاثين عامًا. بدأت الجامعة نشاطها في العام الدراسي 1997–1998 بثلاث كليات و157 طالبًا و32 عضو هيئة تدريس، ونمت لتصبح من الجامعات الخاصة الفاعلة في اسطنبول. تضمّ الجامعة 8 كليات هي: العلوم والآداب، والتربية، والفنون والتصميم، والقانون، والاقتصاد والعلوم الإدارية، والعمارة، والهندسة، والعلوم الصحية، إضافة إلى مدرستين مهنيتين. تتوزع برامجها على 59 قسمًا وبرنامجًا أكاديميًا. تقع الجامعة في الجانب الأوروبي من اسطنبول. تستقطب الجامعة طلابًا دوليين وعربًا، وتُعدّ خيارًا جيدًا للطلاب الراغبين في الدراسة في تركيا في جامعة شاملة بتخصصات متنوعة في قلب اسطنبول.','2026-06-06 16:17:53','2026-06-12 07:54:58','[\"turkish\", \"english\"]','https://www.youtube.com/embed/4xPezQASNOk?si=VPCxEWWiofCljTUe',0.0,NULL,NULL),(203,'جامعة السلطان محمد الفاتح','Fatih Sultan Mehmet Vakıf Üniversitesi','اسطنبول','2010','private','https://fsm.edu.tr/','universities/XSoe7GK9pgdAd7oWLy80ijNGuxUTAoyb0XuNSuJS.png','\"[\\\"university-gallery\\\\/1781085076_6a2933948ebbd.jpeg\\\",\\\"university-gallery\\\\/1781085076_6a29339496538.jpeg\\\",\\\"university-gallery\\\\/1781085076_6a2933949744a.jpeg\\\",\\\"university-gallery\\\\/1781085076_6a29339498387.jpeg\\\",\\\"university-gallery\\\\/1781085076_6a29339499191.jpeg\\\"]\"',171,NULL,'تأسست جامعة السلطان محمد الفاتح (Fatih Sultan Mehmet Vakıf Üniversitesi - FSMVÜ) في مدينة اسطنبول عام 2010 بمبادرة من المديرية العامة للأوقاف في الجمهورية التركية. تستمد الجامعة اسمها وإرثها من السلطان محمد الفاتح فاتح القسطنطينية، وتُموَّل من وقف السلطان محمد الفاتح التاريخي الذي أسسه السلطان نفسه عام 1471 لرعاية مسجد آيا صوفيا، ثم توسّع لاحقًا ليشمل دعم التعليم. تُعدّ الجامعة من المؤسسات الفريدة في تركيا لأنها تجمع بين العمق التاريخي والإسلامي والتعليم الأكاديمي الحديث. تمتلك الجامعة 5 حرم جامعية ضمن شبه الجزيرة التاريخية لاسطنبول، وتضمّ 7 كليات، ومعهدَين، ومدرسة مهنية، ومدرستين للغات، و19 مركزًا بحثيًا. تشمل المجالات الأكاديمية: الفنون والعمارة، والاقتصاد والإدارة والأعمال، والتربية، والهندسة، والعلوم الإسلامية، والقانون، والعلوم الاجتماعية. تتميّز الجامعة بمحافظتها على إرث الفنون الإسلامية وتعليم الخط والعمارة العثمانية، إلى جانب التخصصات الحديثة. تُعدّ FSMVÜ خيارًا مثاليًا للطلاب العرب والمسلمين الراغبين في الدراسة في تركيا في بيئة تجمع بين الأصالة والمعاصرة.','2026-06-06 16:31:22','2026-06-12 08:08:21','[\"turkish\", \"english\"]','https://www.youtube.com/embed/5Y5v4xP_z5k?si=TCq01d1SFa0WVS3c',0.0,NULL,NULL),(204,'جامعة حسن كاليونجو','Hasan Kalyoncu Üniversitesi','غازي عنتاب','2008','private','https://hku.edu.tr/','universities/8w0icF301JqgetMZdnuQQIUFlfsJQKlrZnxTmlHp.png','\"[\\\"university-gallery\\\\/1781102251_6a2976ab57099.jpeg\\\",\\\"university-gallery\\\\/1781102251_6a2976ab5b79b.jpeg\\\",\\\"university-gallery\\\\/1781102251_6a2976ab5bf18.jpeg\\\",\\\"university-gallery\\\\/1781102251_6a2976ab5c645.jpeg\\\",\\\"university-gallery\\\\/1781102251_6a2976ab5cb3b.jpeg\\\"]\"',78,NULL,'تأسست جامعة حسن كاليونجو (Hasan Kalyoncu Üniversitesi - HKU) في مدينة غازي عنتاب جنوب تركيا عام 2008، وكانت تُعرف في البداية باسم \"غازي كنت\" (Gazi Kent) قبل أن يُغيَّر اسمها عام 2012 إلى حسن كاليونجو تكريمًا لرجل الأعمال التركي الشهير. تقع الجامعة في مدينة تاريخية تقع على طريق الحرير القديم، حيث تمتزج فيها الأديان واللغات والثقافات والحضارات، ما يمنح الجامعة بُعدًا حضاريًا فريدًا. بدأت الجامعة بثلاثة أقسام في كلٍّ من كلية الهندسة والعمارة وكلية الاقتصاد والعلوم الإدارية والاجتماعية، ثم أضافت في العام الدراسي 2011–2012 أقسامًا جديدة وافتتحت كلية القانون ومدرسة العلوم الصحية. تضمّ الجامعة اليوم 9 كليات و43 برنامج بكالوريوس في تخصصات متنوعة تشمل العلوم الصحية والهندسة والقانون والفنون الجميلة والعمارة والاقتصاد والعلوم الإدارية والاجتماعية. تمتلك الجامعة شراكات وثيقة مع مجموعة كاليون القابضة، إحدى أكبر المجموعات الصناعية في تركيا، مما يوفّر فرص تدريب وتوظيف للطلاب. تستقطب الجامعة طلابًا عربًا من سوريا والعراق ولبنان والأردن، نظرًا لقربها من الحدود وتكاليف المعيشة المعقولة في غازي عنتاب.','2026-06-06 16:45:12','2026-06-12 07:39:52','[\"turkish\", \"english\"]','https://www.youtube.com/embed/EdngAn6el-M?si=Pi3H4ErFTZv2CPh1',0.0,NULL,NULL),(205,'جامعة الخليج','Haliç Üniversitesi','اسطنبول','1998','private','https://www.halic.edu.tr/','universities/brj1oGpzNa87I0xm3DzxT9QQikjRJufVJa5v8uOi.png','\"[\\\"university-gallery\\\\/1780929833_6a26d529e2cd7.webp\\\",\\\"university-gallery\\\\/1780929833_6a26d529e9e05.webp\\\",\\\"university-gallery\\\\/1780929833_6a26d529eb040.webp\\\",\\\"university-gallery\\\\/1780929833_6a26d529ec2cc.webp\\\",\\\"university-gallery\\\\/1780929833_6a26d529ed2c3.webp\\\"]\"',174,NULL,'تقع جامعة الخليج في مدينة اسطنبول وتعد من اقوى الجامعات التركية الخاصة . لقد تم تأسيس جامعة الخليج في عام 1998 من قبل مؤسسة Leukemia في تركيا . تقدم جامعة الخليج 21 قسمًا أكاديميًا في كلياتها الخمس ، مع ثلاث مدارس ، كلية التمريض ، كلية التربية البدنية والرياضة وكلية العلوم الصحية والمنظم.\r\n\r\nالحرم الجامعي لجامعة الخليج :\r\n\r\nيقع الحرم الجامعي لجامعة الخليج في مدينة اسطنبول تحديدًا في منطقة سوتلوس شارع إمراهور ببيوغلو. يضم الحرم الجامعي لجامعة الخليج على مكتبة ضخمة تم بنائها في العام 1998- 1999 عندما بدأت الجامعة التعليم لأول مرة، كما تضم أجهزة كمبيوتر مخصصة للقراء، كما يستطيع جميع القراء الوصول إلى موارد المكتبة باستخدام أجهزة الكمبيوتر الخاصة بهم، أيضا تحتوي جامعة الخليج على أكثر من 65 مختبر لمختلف التخصصات ومنها مختبر تطبيقات البيولوجيا الجزيئية و برمجة التجارة الإلكترونية للمعلوماتية التجارية، كما تحتوي ايضا الفصول الدراسية وقاعات المؤتمرات المجهزة بأحدث الوسائل التكنولوجية. تقدم جامعة الخليج العديد من الانشطة والبرامج المختلفة للطلاب مثل برامج التنمية الشخصية وبرامج الأعمال العالمية والبرامج التحضيرية وبرامج الصحة والفنون والبرامج الرياضية المتنوعة، وايضًا توفر جامعة الخليج العديد من الدورات والمشروعات منها مشروعات المنسوجات وتصميم الأزياء ودورات برمجة التجارة الإلكترونية للمعلوماتية التجارية ودورات الرياضيات العامة لقسم الأعمال السياحية و دورات الطهي والطبخ ودورة Besyo المراكز الرياضية وإدارة النشاط ودورة الأحياء الجزيئية وعلم الوراثة “الكيمياء العامة ” ودورة تاريخ الفن في التصميم الصناعي ودورات التطبيقات البيولوجيا الجزيئية، بالاضافة الى المقابلات والندوات وورش العمل والرحلات الميدانية.','2026-06-06 17:04:45','2026-06-12 08:21:07','[\"turkish\", \"english\"]','https://www.youtube.com/embed/lr_ifveLNL4?si=hFxEv10LxDQru3Pb',0.0,NULL,NULL),(206,'جامعة اسطنبول جيديك','İstanbul Gedik Üniversitesi','اسطنبول','1994','private','https://www.gedik.edu.tr/','universities/8wq6Ld2CHncrXKWbIWCJwdPscY0nM955VOeOPc06.png','\"[\\\"university-gallery\\\\/1780928958_6a26d1be20d63.webp\\\",\\\"university-gallery\\\\/1780928958_6a26d1be288ac.webp\\\",\\\"university-gallery\\\\/1780928958_6a26d1be29942.webp\\\",\\\"university-gallery\\\\/1780928958_6a26d1be2aad7.webp\\\"]\"',169,NULL,'تأسست جامعة اسطنبول جيديك (İstanbul Gedik Üniversitesi) في مدينة اسطنبول عام 2010 كمدرسة مهنية، ثم رُفعت إلى مرتبة جامعة عام 2011. تُعدّ الجامعة المؤسسة الرائدة لمجموعة \"جيديك\" التي أنشأتها مؤسسة جيديك عام 1994، وهي مجموعة عائلية صناعية تركية تتمتع بأكثر من 59 عامًا من الخبرة في مجالات اللحام وعلوم المواد وعلم المعادن. منح هذا الإرث الصناعي الجامعةَ روابط متينة مع القطاع الصناعي والأعمال، وجعلها مؤسسة مكرّسة للتطوير الأكاديمي بدعم من رجال أعمال ذوي رؤية. تقع الجامعة في الجانب الآسيوي من اسطنبول. تضمّ 5 كليات هي: العلوم الصحية، والهندسة، والاقتصاد والعلوم الإدارية والاجتماعية، والفنون الجميلة والعمارة، والعلوم الرياضية، و3 معاهد للدراسات العليا (العلوم والاجتماعية والصحية)، إضافة إلى 3 مدارس مهنية و95 برنامجًا متنوعًا، ومعهد للدراسات العليا. تتميّز الجامعة بكلية العلوم الرياضية القوية وبأبحاث متخصصة في تكنولوجيا اللحام. تستقطب طلابًا دوليين، وتُعدّ خيارًا جذابًا للطلاب العرب الراغبين في دراسة الهندسة والصحة في تركيا.','2026-06-06 17:24:38','2026-06-12 09:54:20','[\"turkish\", \"english\"]','https://www.youtube.com/embed/wJh4kFxCDsI?si=v7OfMo-zWMzUuocu',0.0,NULL,NULL),(207,'جامعة اسطنبول اوكان','İstanbul Okan Üniversitesi','اسطنبول','1999','private','https://www.okan.edu.tr/','universities/SyEUaxXPj7KMftrNBzcr33wKkOLqaVOsDWUfsIWj.png','\"[\\\"university-gallery\\\\/1780928452_6a26cfc40a08c.webp\\\",\\\"university-gallery\\\\/1780928452_6a26cfc412d85.webp\\\",\\\"university-gallery\\\\/1780928452_6a26cfc414281.webp\\\",\\\"university-gallery\\\\/1780928452_6a26cfc41571a.webp\\\",\\\"university-gallery\\\\/1780928452_6a26cfc416bd3.webp\\\",\\\"university-gallery\\\\/1780928452_6a26cfc418002.webp\\\"]\"',128,NULL,'تأسست جامعة اسطنبول أوكان (İstanbul Okan Üniversitesi) في مدينة اسطنبول عام 1999 بمبادرة من مؤسسة أوكان للثقافة والتعليم والرياضة، وانطلقت بالنشاط الأكاديمي في العام الدراسي 2003–2004. تعود جذور المؤسسة إلى عام 1986 حين أُسّست مؤسسة أوكان للأنشطة الثقافية والتعليمية والرياضية والاجتماعية. تُعدّ جامعة أوكان من أبرز الجامعات الخاصة في تركيا، وتقع في الجانب الآسيوي من اسطنبول، في حرم جامعي حديث في منطقة توزلا، إضافة إلى حرم في وسط اسطنبول لكلية الطب وطب الأسنان. تضمّ الجامعة 10 كليات هي: الطب، وطب الأسنان، والصيدلة، والعلوم الصحية، وإدارة الأعمال والعلوم الإدارية، والإنسانيات والعلوم الاجتماعية، والتربية، والقانون، والهندسة، والفنون والتصميم والعمارة، إلى جانب مدرستين مهنيتين ومدرسة عليا للدراسات العليا. تستقطب الجامعة طلابًا من أكثر من 90 جنسية، وتُعدّ من أكثر الجامعات الخاصة في تركيا انفتاحًا على الطلاب الدوليين والعرب. تقدّم برامجها باللغات التركية والإنكليزية والعربية والروسية والألمانية، وتُعدّ خيارًا متميزًا للراغبين في الدراسة في تركيا، خاصة في تخصصات الطب وطب الأسنان والهندسة وإدارة الأعمال.','2026-06-06 18:09:06','2026-06-12 08:32:07','[\"turkish\", \"english\"]','https://www.youtube.com/embed/_uyLawbosLI?si=DEFWdJRYLpkgYd2y',0.0,NULL,NULL),(208,'جامعة بهشة شهير','Bahçeşehir Üniversitesi','اسطنبول','1998','private','https://bau.edu.tr/','universities/9OnsRmEE0bCemSPpr9AOiJJonC9bl2bX3fddHUL4.png','\"[\\\"university-gallery\\\\/1780926537_6a26c849e51ae.webp\\\",\\\"university-gallery\\\\/1780926537_6a26c849e802a.webp\\\",\\\"university-gallery\\\\/1780926537_6a26c849e88c3.webp\\\",\\\"university-gallery\\\\/1780926537_6a26c849e8fd6.webp\\\",\\\"university-gallery\\\\/1780926537_6a26c849e9dff.webp\\\",\\\"university-gallery\\\\/1780926537_6a26c849ea7dc.webp\\\"]\"',64,NULL,'تأسست جامعة بهشة شهير (Bahçeşehir Üniversitesi - BAU) في مدينة اسطنبول عام 1998 بمبادرة من مؤسسة بهشة شهير-أوغور للتعليم بترخيص من البرلمان التركي. أسّست الجامعة شراكة استراتيجية وأكاديمية مع جامعة سان دييغو الحكومية (San Diego State University) في فبراير 1998، واستقبلت أوّل دفعاتها في العام الدراسي 1999–2000. تُعدّ الجامعة من أبرز الجامعات الخاصة في تركيا، وتتميّز بشبكتها الدولية BAU Global التي تشمل شراكات مع أكثر من 200 جامعة حول العالم وفروعًا أكاديمية في برلين وواشنطن وسيليكون فالي وروما وهونغ كونغ وتورنتو. يقع الحرم الرئيسي في حي بشكتاش الراقي على ضفاف مضيق البوسفور، وتمتلك الجامعة 6 حرم جامعية في اسطنبول. تضمّ الجامعة 9 كليات ومدرسة عليا للعلوم التطبيقية ومعهد موسيقى ومدرسة لغات أجنبية ومدرسة مهنية ومعهد للدراسات العليا، وتقدّم أكثر من 100 برنامج بكالوريوس وأكثر من 200 برنامج دراسات عليا. تشمل الكليات: الاقتصاد والعلوم الإدارية والاجتماعية، والاتصال، والعمارة والتصميم، والقانون، والهندسة، والطب، والتربية، والصحة، والفنون. تستقطب الجامعة طلابًا عربًا ودوليين بشكل كبير، وتُعدّ من أبرز خيارات الدراسة في تركيا في موقع متميز على البوسفور.','2026-06-06 18:25:59','2026-06-12 10:03:26','[\"turkish\", \"english\"]','https://www.youtube.com/embed/95HHVvssl-s?si=7lvMoJ9r3uthWIbf',0.0,NULL,NULL),(209,'جامعة إسطنبول توبكابي','İstanbul Topkapı Üniversitesi','اسطنبول','2016','private','https://www.topkapi.edu.tr/','universities/I893CrxgGIrDCXOhbu9qVA55pYOfP5F1r9gmgOKa.jpg','\"[\\\"university-gallery\\\\/1780916696_6a26a1d8c1f55.jpeg\\\",\\\"university-gallery\\\\/1780916696_6a26a1d8c7112.jpeg\\\",\\\"university-gallery\\\\/1780916696_6a26a1d8c7de2.jpeg\\\",\\\"university-gallery\\\\/1780916696_6a26a1d8c873b.jpeg\\\"]\"',184,NULL,'جامعة توبكابي تعد واحدة من الجامعات الرائدة التي تسعى إلى دمج التعليم النظري بالتطبيق العملي بهدف تخريج كوادر مؤهلة قادرة على مواكبة تطورات العصر. تضم الجامعة مجموعة متنوعة من الكليات والمعاهد التي تغطي مختلف التخصصات الأكاديمية والمهنية.\r\n\r\nتتميز كلية الطب في جامعة توبكابي بالتركيز على الأبحاث العلمية في مجال الرعاية الصحية وتدريب الأطباء المتخصصين بما يساهم في تطوير الخدمات الصحية على المستوى المحلي والدولي. كما تقدم كلية طب الأسنان برامج دراسية تجمع بين المعرفة العلمية والتدريب العملي لتأهيل أطباء أسنان محترفين في مجالات الوقاية والعلاج.\r\n\r\nتهدف كلية الهندسة في جامعة توبكابي إلى إعداد جيل من المهندسين القادرين على تقديم حلول مبتكرة للتحديات التكنولوجية، مع التركيز على تطوير البرمجيات والهندسة الميكانيكية والإلكترونية. كما توفر كلية العلوم الاجتماعية والإنسانية برامج تعليمية تركز على تحليل الظواهر الاجتماعية وصياغة استراتيجيات للتعامل معها بطرق فعّالة.\r\n\r\nيتميز الحرم الجامعي لجامعة توبكابي بتصميمه العصري والمرافق المجهزة بأحدث التقنيات التي تدعم عملية التعلم والبحث العلمي. الجامعة تؤمن بمبدأ \"التعليم مدى الحياة\" وتسعى جاهدة لتوفير بيئة تعليمية محفزة تدعم التطور المستمر لطلابها وتساعدهم في تحقيق أهدافهم الأكاديمية والمهنية.','2026-06-06 18:58:46','2026-06-12 06:38:18','[\"turkish\", \"english\"]','https://www.youtube.com/embed/UDRwKmhbJUg?si=FsqDJER5YXZ3zIPH',0.0,NULL,NULL),(210,'جامعة فنربهشة','Fenerbahçe Üniversitesi','اسطنبول','2016','private','https://fbu.edu.tr/','universities/eDR8CCTDaVGD5sfeDFADsN2CX4jLVTfOg9I4sExM.png','\"[\\\"university-gallery\\\\/1781162498_6a2a620291529.jpeg\\\",\\\"university-gallery\\\\/1781162498_6a2a620298be4.jpeg\\\",\\\"university-gallery\\\\/1781162498_6a2a620299f48.jpeg\\\",\\\"university-gallery\\\\/1781162498_6a2a62029b1b6.jpeg\\\",\\\"university-gallery\\\\/1781162498_6a2a62029c12d.jpeg\\\",\\\"university-gallery\\\\/1781162498_6a2a62029d3c4.jpeg\\\"]\"',180,NULL,'تأسست جامعة فنربهشة (Fenerbahçe Üniversitesi) في مدينة اسطنبول عام 2016 بمبادرة من مؤسسة فنربهشة للتعليم والثقافة والصحة التابعة لنادي فنربهشة الرياضي العريق، وحصلت على الشخصية الاعتبارية بموجب القانون المنشور في الجريدة الرسمية بتاريخ 24 نوفمبر 2016. تقع الجامعة في قلب الجانب الآسيوي من اسطنبول، وتُعدّ من الجامعات الخاصة الديناميكية والمبتكرة التي رسّخت مكانتها بسرعة في المشهد الأكاديمي التركي. تستفيد الجامعة من إرث وعلامة نادي فنربهشة الذي يُعدّ أحد أكبر الأندية الرياضية والاجتماعية في تركيا والعالم الإسلامي. تضمّ الجامعة ست كليات للبكالوريوس ومدرسة مهنية، إضافة إلى معهد الدراسات العليا الذي يقدّم خمسة برامج ماجستير وبرنامج دكتوراه. تشمل الكليات: الهندسة، وإدارة الأعمال، والعلوم والآداب، والعلوم الصحية، والاتصال، والرياضة، والفنون والتصميم. تُوفّر الجامعة خدمات تعليمية وثقافية واجتماعية في حرم جامعي حديث ومتطور، مما يجعلها وجهة جذابة للطلاب الدوليين والعرب الراغبين في الدراسة في تركيا والاستفادة من قيمة العلامة الرياضية والثقافية لفنربهشة.','2026-06-06 19:19:19','2026-06-12 07:51:20','[\"turkish\", \"english\"]','https://www.youtube.com/embed/XK3h1Feg0lk?si=Tq-bO4LI43nMS1GZ',0.0,NULL,NULL),(211,'جامعة بيلكينت','İhsan Doğramacı Bilkent Üniversitesi','انقرة','1984','private','https://bilkent.edu.tr/','universities/bTHfFfeQi86HKppnETByEK8ZpmO9BtSFPacWsjcG.png','\"[\\\"university-gallery\\\\/1781098321_6a296751b7136.jpeg\\\",\\\"university-gallery\\\\/1781098321_6a296751bba77.jpeg\\\",\\\"university-gallery\\\\/1781098321_6a296751bc036.jpeg\\\",\\\"university-gallery\\\\/1781098321_6a296751bc540.jpeg\\\",\\\"university-gallery\\\\/1781098321_6a296751bca4e.jpeg\\\"]\"',11,NULL,'تأسست جامعة بيلكنت (Bilkent Üniversitesi) في العاصمة التركية أنقرة في 20 أكتوبر 1984 على يد البروفيسور إحسان دوغرامجي عبر مؤسساته الثلاث (التعليم والبحث العلمي والصحة)، لتكون أوّل جامعة خاصة غير ربحية في تركيا. اسم \"بيلكنت\" اختصار لعبارة \"بيليم كنتي\" التي تعني \"مدينة العلم\" بالتركية، تجسيدًا لرؤية مؤسسها في إنشاء جامعة بحثية بمعايير أمريكية. بدأت الجامعة باستقبال أوّل دفعاتها عام 1986 بـ386 طالبًا، ونمت لتستقبل اليوم أكثر من 12,000 طالب موزّعين على 9 كليات ومدرستين و3 مدارس مهنية و3 مدارس عليا للدراسات العليا. تتميّز كلية الهندسة بسمعة أكاديمية متميزة، وكانت كلية إدارة الأعمال أوّل كلية أعمال في تركيا تحصل على اعتماد AACSB المرموق. تستوحي الجامعة فلسفتها من نموذج الجامعات الأمريكية النخبوية الذي اطّلع عليه مؤسسها أثناء عمله في جامعتي هارفارد وواشنطن في الأربعينيات. تعتمد الجامعة الإنكليزية في جميع برامجها، وتُصنَّف ضمن أفضل جامعات تركيا والمنطقة، وتُعدّ وجهة مرموقة للطلاب الدوليين الراغبين في الدراسة في تركيا.','2026-06-06 19:22:51','2026-06-10 10:32:01','[\"english\"]','https://www.youtube.com/embed/dsBggwd5-WU?si=qR_oqDPlLNaayvgF',0.0,NULL,NULL),(212,'جامعة اسطنبول ميديبول','İstanbul Medipol Üniversitesi','اسطنبول','2009','private','https://www.medipol.edu.tr/','universities/rr38OPWNuaB8dpDqhu2DVxLUKtl5y32vF3OUdBzg.png','\"[\\\"university-gallery\\\\/1780927192_6a26cad8c68ce.webp\\\",\\\"university-gallery\\\\/1780927192_6a26cad8ca6a4.webp\\\",\\\"university-gallery\\\\/1780927192_6a26cad8caf5a.webp\\\",\\\"university-gallery\\\\/1780927192_6a26cad8cb771.webp\\\",\\\"university-gallery\\\\/1780927192_6a26cad8cbcf6.webp\\\"]\"',40,NULL,'تأسست جامعة اسطنبول ميديبول (İstanbul Medipol Üniversitesi) في مدينة اسطنبول عام 2009 بمبادرة من مؤسسة تركيا للتعليم والصحة والبحث، التي أسسها فخر الدين قوجة (Fahrettin Koca)، وزير الصحة في الحكومة التركية السابعة والستين. تُعدّ الجامعة من أكبر الجامعات الخاصة في تركيا والشرق الأوسط، وتتمحور رسالتها حول التعليم الطبي والعلوم الصحية. تستضيف الجامعة 49,757 طالبًا، يشمل 33,216 طالب بكالوريوس و1,037 طالب دراسات عليا و14,722 طالب درجة زمالة، وتمتلك 1,538 عضو هيئة تدريس و2,572 موظفًا إداريًا. تضمّ الجامعة 12 كلية و5 معاهد و4 مدارس مهنية، تشمل كليات: الطب، وطب الأسنان، والصيدلة، والهندسة، والقانون، والاتصال، والفنون الجميلة، والعلوم الصحية، والعلوم الاجتماعية. تقدّم 74 برنامج بكالوريوس، 24 منها باللغة الإنكليزية. تمتلك الجامعة مستشفى ميديبول ميغا الجامعي قرب باشاك شهير في باغجلار، الذي حصل على اعتماد \"المركز الطبي الأكاديمي\" من Joint Commission International. تستقطب الجامعة طلابًا عربًا ودوليين بشكل مكثف، وتُعدّ من أبرز وجهات دراسة الطب في تركيا.','2026-06-06 20:08:47','2026-06-12 09:45:59','[\"turkish\", \"english\"]','https://www.youtube.com/embed/5PYAr4du9OM?si=gnQdZaVDRpm7-hPs',0.0,NULL,NULL),(213,'جامعة اسطنبول جيليشيم','İstanbul Gelişim Üniversitesi','اسطنبول','2008','private','https://www.gelisim.edu.tr/','universities/pNqntoqcInX42WUwR90HRjhvLLmJP6eIOhXF2se4.png','\"[\\\"university-gallery\\\\/1780930693_6a26d885806f8.webp\\\",\\\"university-gallery\\\\/1780930693_6a26d88582f97.webp\\\",\\\"university-gallery\\\\/1780930693_6a26d885835b2.webp\\\",\\\"university-gallery\\\\/1780930693_6a26d88583d3d.webp\\\",\\\"university-gallery\\\\/1780930693_6a26d885842ab.webp\\\",\\\"university-gallery\\\\/1780930693_6a26d885847ba.webp\\\"]\"',131,NULL,'جامعة اسطنبول جيليشيم في إسطنبول تبرز كمؤسسة تعليمية رائدة تمزج بين الإرث الثقافي والحداثة، وتعرض مساقاتها باللغات الإنجليزية والتركية لتلبية احتياجات الطلاب المحليين والدوليين. بفضل مجتمعها الطلابي المتنوع الذي يشمل أكثر من 20 ألف طالب وكادرها التعليمي والإداري الذي يزيد عن 1500 فرد، تحرص جامعة اسطنبول جيليشيم على تقديم تعليم من الطراز الأول. الجامعة تفخر بتنوعها الأكاديمي من خلال 11 كلية، 3 معاهد للدراسات العليا، و3 مدارس مهنية، إلى جانب 5 مراكز بحثية متخصصة. جامعة اسطنبول جيليشيم ملتزمة بتأهيل طلابها ليكونوا جاهزين للمنافسة في سوق العمل الدولي، مع التركيز على الابتكار والتميز البحثي، مما يضمن تخريج أجيال مؤهلة لمواجهة تحديات المستقبل.','2026-06-06 21:12:49','2026-06-12 08:43:20','[\"turkish\", \"english\"]','https://www.youtube.com/embed/UdhPeirpVeg?si=2OsG1SZ6Br-wCA-a',0.0,NULL,NULL),(214,'جامعة اسطنبول ايدن','İstanbul Aydın Üniversitesi','اسطنبول','2003','private','https://www.aydin.edu.tr/','universities/B1ktO4awrKdKYsRHSuKt2ycbRIU3aJs8cxrSICMn.png','\"[\\\"university-gallery\\\\/1780928734_6a26d0de1e15b.webp\\\",\\\"university-gallery\\\\/1780928734_6a26d0de26c48.webp\\\",\\\"university-gallery\\\\/1780928734_6a26d0de28016.webp\\\",\\\"university-gallery\\\\/1780928734_6a26d0de291a5.webp\\\",\\\"university-gallery\\\\/1780928734_6a26d0de2a356.webp\\\",\\\"university-gallery\\\\/1780928734_6a26d0de2b3cf.webp\\\"]\"',129,NULL,'تُعدّ جامعة إيدن واحدة من الجامعات الرائدة التي تلتزم بتطوير المعرفة العلمية وتوظيفها في خدمة المجتمع. تضم الجامعة مجموعة متنوعة من الكليات ومراكز التعليم العالي التي تغطي مختلف التخصصات.\r\n\r\nتتميز كلية الطب في جامعة إيدن بتركيزها على الأبحاث العلمية في مجال الرعاية الصحية وتأهيل المتخصصين المؤهلين في هذا القطاع. بالمثل، تعمل كلية طب الأسنان بالجامعة على الجمع بين الأبحاث العلمية في مجال الصحة الفموية وتدريب الطلاب على المهارات النظرية والعملية.\r\n\r\nتهدف كلية الهندسة والعلوم الطبيعية إلى تخريج طلاب مؤهلين لقيادة المستقبل التكنولوجي، في حين تقدم كلية العلوم الإنسانية والاجتماعية برامج دراسية تركز على تحليل ومواجهة التحديات الاجتماعية بحلول مبتكرة وفعالة. كما توفر كلية علوم الصحة دورات متقدمة في إدارة وتنفيذ الخدمات الصحية.\r\n\r\nيتسم الحرم الجامعي لجامعة إيدن ببنيته التحتية المتطورة والمجهزة لتلبية جميع احتياجات الطلاب، حيث يضم الحرم الجامعي آلاف الطلاب الذين يستفيدون من مرافقه المتنوعة. تعتمد الجامعة فلسفة “تأثير الفراشة”، مؤمنة بأن التغييرات الصغيرة يمكن أن تحدث فروقاً كبيرة، وتسعى جامعة إيدن لتوفير تجربة تعليمية شاملة ومستمرة لجميع طلابها.','2026-06-06 22:02:06','2026-06-11 05:50:39','[\"turkish\", \"english\"]','https://www.youtube.com/embed/7ieJUL9VXbc?si=yKn96Uo8EBmO-aRh',0.0,NULL,NULL);
