--
-- Table structure for table `university_quotas`
--

DROP TABLE IF EXISTS `university_quotas`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `university_quotas` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `competition_number` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `university_name_tr` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `university_name_ar` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `institute` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fee` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `city` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `registration_start` date DEFAULT NULL,
  `registration_end` date DEFAULT NULL,
  `results_date` date DEFAULT NULL,
  `accepted_certificates` text COLLATE utf8mb4_unicode_ci,
  `details` text COLLATE utf8mb4_unicode_ci,
  `application_method` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `local_rank` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `university_id` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `university_quotas_university_id_foreign` (`university_id`),
  CONSTRAINT `university_quotas_university_id_foreign` FOREIGN KEY (`university_id`) REFERENCES `universities` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=122 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

